const ORCHESTRATOR_VOICE_TURN_TIMEOUT_MS = 60000;
const ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT = 256;
const ORCHESTRATOR_VOICE_RING_CENTER = 50;
const ORCHESTRATOR_VOICE_RING_MIN_RADIUS = 35.8;
const ORCHESTRATOR_VOICE_RING_BASE_RADIUS = 39.2;
const ORCHESTRATOR_VOICE_RING_MAX_RADIUS = 46.2;
const ORCHESTRATOR_VOICE_NOISE_CALIBRATION_MS = 700;
const ORCHESTRATOR_VOICE_NOISE_MARGIN = 0.035;
const ORCHESTRATOR_VOICE_ENVELOPE_MARGIN = 0.0015;
const ORCHESTRATOR_VOICE_SAMPLE_SOURCE_START = 0.5;
const ORCHESTRATOR_VOICE_SAMPLE_SOURCE_SPAN = 0.5;
const EMPTY_ORCHESTRATOR_VOICE_STATS = {
  bufferMs: 0,
  frequencyBands: [],
  peak: 0,
  rms: 0,
  timeDomainSamples: [],
};

function clampOrchestratorVoiceLevel(value) {
  const level = Number(value);

  if (!Number.isFinite(level)) {
    return 0;
  }

  return Math.max(0, Math.min(100, level));
}

function getOrchestratorVoiceLevel(stats) {
  const rms = Math.max(0, Number(stats?.rms || 0));
  const peak = Math.max(0, Number(stats?.peak || 0));
  const rmsLevel = Math.pow(Math.min(1, rms * 18), 0.74) * 100;
  const peakLevel = Math.pow(Math.min(1, peak * 2.8), 0.85) * 62;

  return Math.round(clampOrchestratorVoiceLevel(Math.max(rmsLevel, peakLevel)));
}

function getOrchestratorVoiceFrequencyBand(
  frequencyBands,
  pointIndex,
  pointCount = ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
) {
  if (!Array.isArray(frequencyBands) || frequencyBands.length === 0) {
    return null;
  }

  const bandPosition = (pointIndex / pointCount) * frequencyBands.length;
  const lowerIndex = Math.floor(bandPosition) % frequencyBands.length;
  const upperIndex = (lowerIndex + 1) % frequencyBands.length;
  const mix = bandPosition - Math.floor(bandPosition);
  const lowerValue = clampOrchestratorVoiceLevel(Number(frequencyBands[lowerIndex] || 0) * 100) / 100;
  const upperValue = clampOrchestratorVoiceLevel(Number(frequencyBands[upperIndex] || 0) * 100) / 100;

  return lowerValue + ((upperValue - lowerValue) * mix);
}

function getOrchestratorVoiceWaveformSample(
  timeDomainSamples,
  pointIndex,
  pointCount = ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
) {
  if (!Array.isArray(timeDomainSamples) || timeDomainSamples.length === 0) {
    return null;
  }

  const sourceLength = timeDomainSamples.length;
  const sourceStart = Math.floor(sourceLength * ORCHESTRATOR_VOICE_SAMPLE_SOURCE_START);
  const sourceSpan = Math.max(1, Math.floor(sourceLength * ORCHESTRATOR_VOICE_SAMPLE_SOURCE_SPAN));
  const wrappedPoint = ((pointIndex % pointCount) + pointCount) % pointCount;
  const samplePosition = (wrappedPoint / pointCount) * sourceSpan;
  const lowerOffset = Math.floor(samplePosition) % sourceSpan;
  const upperOffset = (lowerOffset + 1) % sourceSpan;
  const lowerIndex = (sourceStart + lowerOffset) % sourceLength;
  const upperIndex = (sourceStart + upperOffset) % sourceLength;
  const mix = samplePosition - Math.floor(samplePosition);
  const lowerValue = Math.max(0, Math.min(1, Number(timeDomainSamples[lowerIndex] || 0)));
  const upperValue = Math.max(0, Math.min(1, Number(timeDomainSamples[upperIndex] || 0)));

  return lowerValue + ((upperValue - lowerValue) * mix);
}

function getOrchestratorVoiceEnvelopeStats(
  timeDomainSamples,
  pointCount = ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
) {
  if (!Array.isArray(timeDomainSamples) || timeDomainSamples.length === 0) {
    return {
      average: 0,
      maximum: 0,
      minimum: 0,
      range: 0,
    };
  }

  let maximum = 0;
  let minimum = 1;
  let sum = 0;

  for (let index = 0; index < pointCount; index += 1) {
    const sample = getOrchestratorVoiceWaveformSample(timeDomainSamples, index, pointCount) || 0;
    maximum = Math.max(maximum, sample);
    minimum = Math.min(minimum, sample);
    sum += sample;
  }

  return {
    average: sum / pointCount,
    maximum,
    minimum,
    range: maximum - minimum,
  };
}

function getOrchestratorVoiceLocalEnvelopeAverage(
  timeDomainSamples,
  pointIndex,
  pointCount = ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
) {
  if (!Array.isArray(timeDomainSamples) || timeDomainSamples.length === 0) {
    return 0;
  }

  const sampleRadius = 12;
  let weightedSum = 0;
  let weightSum = 0;

  for (let offset = -sampleRadius; offset <= sampleRadius; offset += 1) {
    const sample = getOrchestratorVoiceWaveformSample(
      timeDomainSamples,
      (pointIndex + offset + pointCount) % pointCount,
      pointCount,
    );
    const weight = sampleRadius + 1 - Math.abs(offset);

    weightedSum += (sample || 0) * weight;
    weightSum += weight;
  }

  return weightSum > 0 ? weightedSum / weightSum : 0;
}

function getOrchestratorVoiceRingPoint(radius, angle) {
  return {
    x: ORCHESTRATOR_VOICE_RING_CENTER + Math.cos(angle) * radius,
    y: ORCHESTRATOR_VOICE_RING_CENTER + Math.sin(angle) * radius,
  };
}

function getOrchestratorVoiceCircularValue(values, index) {
  if (!Array.isArray(values) || values.length === 0) {
    return 0;
  }

  return values[((index % values.length) + values.length) % values.length] || 0;
}

function getOrchestratorVoiceSmoothedEnvelopeValue(values, index) {
  return (
    (getOrchestratorVoiceCircularValue(values, index) * 0.34)
    + (getOrchestratorVoiceCircularValue(values, index - 1) * 0.19)
    + (getOrchestratorVoiceCircularValue(values, index + 1) * 0.19)
    + (getOrchestratorVoiceCircularValue(values, index - 2) * 0.1)
    + (getOrchestratorVoiceCircularValue(values, index + 2) * 0.1)
    + (getOrchestratorVoiceCircularValue(values, index - 3) * 0.04)
    + (getOrchestratorVoiceCircularValue(values, index + 3) * 0.04)
  );
}

function getOrchestratorVoiceBandAboveFloor(
  frequencyBands,
  noiseFloorBands,
  pointIndex,
  pointCount = ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
) {
  const rawEnergy = getOrchestratorVoiceFrequencyBand(frequencyBands, pointIndex, pointCount);
  const floorEnergy = getOrchestratorVoiceFrequencyBand(noiseFloorBands, pointIndex, pointCount) || 0;

  if (rawEnergy === null) {
    return null;
  }

  return Math.max(0, rawEnergy - floorEnergy - ORCHESTRATOR_VOICE_NOISE_MARGIN);
}

function getOrchestratorVoiceWaveformTarget(
  index,
  level,
  active,
  timeDomainSamples = [],
  envelopeStats = {},
  frequencyBands = [],
  noiseFloorBands = [],
  animationPhase = 0,
) {
  const normalizedLevel = active ? clampOrchestratorVoiceLevel(level) / 100 : 0;
  const activityGate = active
    ? Math.max(0, Math.min(1, (normalizedLevel - 0.035) / 0.58))
    : 0;
  const pointAngle = (-Math.PI / 2)
    + ((index / ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT) * Math.PI * 2);
  const waveformSample = getOrchestratorVoiceWaveformSample(
    timeDomainSamples,
    index,
    ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
  );
  const fallbackSample = Math.max(
    0,
    (
      Math.sin(pointAngle * 2.8 + animationPhase * 1.2)
      + (Math.cos(pointAngle * 5.2 - animationPhase * 0.7) * 0.44)
    ) * 0.003,
  );
  const envelopeSample = waveformSample ?? fallbackSample;
  const localAverage = getOrchestratorVoiceLocalEnvelopeAverage(
    timeDomainSamples,
    index,
    ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
  );
  const frameAverage = Math.max(0, Number(envelopeStats.average || 0));
  const dynamicRange = Math.max(
    Number(envelopeStats.range || 0),
    frameAverage * 0.28,
    0.003,
  );
  const localContrast = Math.max(
    0,
    envelopeSample - localAverage - ORCHESTRATOR_VOICE_ENVELOPE_MARGIN,
  );
  const frameContrast = Math.max(
    0,
    envelopeSample - frameAverage - ORCHESTRATOR_VOICE_ENVELOPE_MARGIN,
  );
  const contrastSample = Math.max(localContrast * 1.45, frameContrast * 0.9);
  const envelopeLift = Math.tanh((contrastSample / dynamicRange) * (2.2 + (normalizedLevel * 2.6)));
  const frequencyEnergy = getOrchestratorVoiceBandAboveFloor(
    frequencyBands,
    noiseFloorBands,
    index,
    ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
  );
  const previousEnergy = getOrchestratorVoiceBandAboveFloor(
    frequencyBands,
    noiseFloorBands,
    (index - 1 + ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT) % ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
    ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
  ) || 0;
  const nextEnergy = getOrchestratorVoiceBandAboveFloor(
    frequencyBands,
    noiseFloorBands,
    (index + 1) % ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
    ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT,
  ) || 0;
  const bandEnergy = frequencyEnergy ?? 0;
  const neighborAverage = (previousEnergy + nextEnergy) / 2;
  const localPeak = Math.max(0, bandEnergy - (neighborAverage * 0.72));
  const localLift = Math.min(0.1, Math.pow(localPeak * 7, 0.76) * 0.08);
  const idleDrift = active
    ? Math.max(0, Math.sin(pointAngle * 3 + animationPhase * 0.85) * 0.012)
    : 0;

  return active
    ? Math.max(0, Math.min(1, (envelopeLift * activityGate) + localLift + idleDrift))
    : 0;
}

function drawOrchestratorVoiceSmoothPath(context, points) {
  if (!points.length) {
    return;
  }

  const count = points.length;
  context.moveTo(points[0].x, points[0].y);

  for (let index = 0; index < count; index += 1) {
    const previous = points[(index - 1 + count) % count];
    const current = points[index];
    const next = points[(index + 1) % count];
    const afterNext = points[(index + 2) % count];
    const controlOne = {
      x: current.x + ((next.x - previous.x) / 6),
      y: current.y + ((next.y - previous.y) / 6),
    };
    const controlTwo = {
      x: next.x - ((afterNext.x - current.x) / 6),
      y: next.y - ((afterNext.y - current.y) / 6),
    };

    context.bezierCurveTo(controlOne.x, controlOne.y, controlTwo.x, controlTwo.y, next.x, next.y);
  }

  context.closePath();
}

function getForgeThemeMode() {
  if (typeof document === "undefined") {
    return "dark";
  }

  return document.documentElement?.dataset?.forgeTheme === "light" ? "light" : "dark";
}

function getForgeSpaceMode() {
  if (typeof document === "undefined") {
    return "workspaces";
  }

  return document.documentElement?.dataset?.forgeSpace === "loopspaces" ? "loopspaces" : "workspaces";
}

function getLoopspaceTriggerPayload(value) {
  const candidates = [
    value?.payload,
    value?.sync,
    value?.response,
    value?.data,
    value?.event,
    value,
  ].filter(Boolean);
  for (const candidate of candidates) {
    if (
      Array.isArray(candidate?.triggers)
      || Array.isArray(candidate?.loopspace_triggers)
      || Array.isArray(candidate?.loopspaceTriggers)
      || Array.isArray(candidate?.runs)
      || Array.isArray(candidate?.trigger_runs)
      || Array.isArray(candidate?.triggerRuns)
    ) {
      return candidate;
    }
    if (candidate?.payload && candidate.payload !== candidate) {
      const nested = getLoopspaceTriggerPayload(candidate.payload);
      if (
        Array.isArray(nested?.triggers)
        || Array.isArray(nested?.loopspace_triggers)
        || Array.isArray(nested?.loopspaceTriggers)
        || Array.isArray(nested?.runs)
        || Array.isArray(nested?.trigger_runs)
        || Array.isArray(nested?.triggerRuns)
      ) {
        return nested;
      }
    }
  }
  return value || {};
}

function normalizeLoopspaceTriggerRows(value) {
  const payload = getLoopspaceTriggerPayload(value);
  const rows = payload?.triggers || payload?.loopspace_triggers || payload?.loopspaceTriggers || [];
  return Array.isArray(rows)
    ? rows.map((row) => {
      const id = String(row?.id || row?.trigger_id || row?.triggerId || "").trim();
      const config = row?.config && typeof row.config === "object" ? row.config : {};
      const loopspaceIds = Array.isArray(row?.loopspaceIds)
        ? row.loopspaceIds
        : Array.isArray(row?.loopspace_ids)
          ? row.loopspace_ids
          : [];
      return {
        ...row,
        id,
        config,
        enabled: row?.enabled !== false,
        loopspaceIds: loopspaceIds.map((item) => String(item || "").trim()).filter(Boolean),
        name: String(row?.name || id || "Trigger").trim(),
        type: String(row?.type || row?.trigger_type || row?.triggerType || "cron").trim().toLowerCase(),
        nextDueAtMs: Number(row?.nextDueAtMs || row?.next_due_at_ms || 0) || 0,
        lastRunAtMs: Number(row?.lastRunAtMs || row?.last_run_at_ms || 0) || 0,
        lastStatus: String(row?.lastStatus || row?.last_status || "").trim(),
        webhookAuthMode: normalizeLoopspaceWebhookAuthMode(
          row?.webhookAuthMode
          || row?.webhook_auth_mode
          || config.webhookAuthMode
          || config.webhook_auth_mode,
        ),
        webhookPath: String(row?.webhookPath || row?.webhook_path || config.webhookPath || config.webhook_path || "").trim(),
        webhookSecret: String(row?.webhookSecret || row?.webhook_secret || "").trim(),
        webhookSecretHint: String(row?.webhookSecretHint || row?.webhook_secret_hint || "").trim(),
        webhookSignatureToleranceSec: Number(row?.webhookSignatureToleranceSec || row?.webhook_signature_tolerance_sec || 300) || 300,
      };
    }).filter((row) => row.id)
    : [];
}

function normalizeLoopspaceTriggerRuns(value) {
  const payload = getLoopspaceTriggerPayload(value);
  const rows = payload?.runs || payload?.trigger_runs || payload?.triggerRuns || [];
  return Array.isArray(rows)
    ? rows.map((row) => ({
      ...row,
      id: String(row?.id || row?.run_id || row?.runId || "").trim(),
      status: String(row?.status || "").trim(),
      triggerId: String(row?.triggerId || row?.trigger_id || "").trim(),
      createdAtMs: Number(row?.createdAtMs || row?.created_at_ms || 0) || 0,
    })).filter((row) => row.id)
    : [];
}

function normalizeLoopspaceTriggerSnapshot(value) {
  return {
    runs: normalizeLoopspaceTriggerRuns(value),
    triggers: normalizeLoopspaceTriggerRows(value),
  };
}

function getLoopspaceListPayload(value) {
  const candidates = [value?.payload, value?.sync, value?.response, value?.data, value].filter(Boolean);
  for (const candidate of candidates) {
    if (Array.isArray(candidate?.loopspaces)) {
      return candidate;
    }
    if (candidate?.payload && candidate.payload !== candidate) {
      const nested = getLoopspaceListPayload(candidate.payload);
      if (Array.isArray(nested?.loopspaces)) return nested;
    }
  }
  return value || {};
}

function normalizeLoopspaceRows(value) {
  const payload = getLoopspaceListPayload(value);
  const rows = Array.isArray(payload?.loopspaces) ? payload.loopspaces : [];
  return rows.map((row) => ({
    ...row,
    id: String(row?.id || row?.loopspace_id || row?.loopspaceId || "").trim(),
    name: String(row?.name || row?.loopspace_name || row?.loopspaceName || "Loop").trim(),
  })).filter((row) => row.id);
}

function formatLoopspaceTriggerTime(value) {
  const ms = Number(value || 0);
  if (!Number.isFinite(ms) || ms <= 0) return "";
  try {
    return new Date(ms).toLocaleString([], {
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      month: "short",
    });
  } catch {
    return "";
  }
}

function normalizeLoopspaceWebhookBaseUrl(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const withoutSlash = raw.replace(/\/+$/, "");
  const lower = withoutSlash.toLowerCase();
  if (lower.startsWith("wss://")) return `https://${withoutSlash.slice(6)}`;
  if (lower.startsWith("ws://")) return `http://${withoutSlash.slice(5)}`;
  return withoutSlash;
}

function getLoopspaceWebhookCopyUrl(path, baseUrl) {
  const rawPath = String(path || "").trim();
  if (!rawPath) return "";
  if (/^https?:\/\//i.test(rawPath)) return rawPath;
  const normalizedBase = normalizeLoopspaceWebhookBaseUrl(baseUrl);
  if (!normalizedBase) return "";
  const normalizedPath = rawPath.startsWith("/") ? rawPath : `/${rawPath}`;
  return `${normalizedBase}${normalizedPath}`;
}

const LOOPSPACE_TRIGGER_TYPE_OPTIONS = [
  { icon: Schedule, label: "Cron", value: "cron" },
  { icon: Webhook, label: "Webhook", value: "webhook" },
  { icon: AdsClick, label: "Manual", value: "manual" },
];

const LOOPSPACE_WEBHOOK_AUTH_OPTIONS = [
  { label: "Signed", value: "signed_hmac" },
  { label: "Public URL", value: "public_token" },
];

const LOOPSPACE_TRIGGER_SCHEDULE_PRESETS = [
  { id: "5m", label: "5m", value: "@every 5m" },
  { id: "15m", label: "15m", value: "@every 15m" },
  { id: "hourly", label: "1h", value: "@hourly" },
  { id: "daily", label: "24h", value: "@daily" },
  { id: "custom", label: "Custom", value: "" },
];

const LOOPSPACE_TRIGGER_DRAG_MIME = "application/x-diffforge-loopspace-trigger";
const LOOPSPACE_TRIGGER_DRAG_KIND = "loopspace_trigger_ref";
const LOOPSPACE_GRAPH_POINTER_DRAG_EVENT = "diffforge:loopspace-graph-pointer-drag-start";

function getLoopspaceTriggerTypeLabel(type) {
  if (type === "webhook") return "Webhook";
  if (type === "manual") return "Manual";
  return "Cron";
}

function getLoopspaceTriggerTypeIcon(type) {
  if (type === "webhook") return Webhook;
  if (type === "manual") return AdsClick;
  return Schedule;
}

function normalizeLoopspaceWebhookAuthMode(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (["public", "public_token", "bearer", "bearer_path", "url_token"].includes(raw)) {
    return "public_token";
  }
  if (["signed", "signed_hmac", "hmac", "stripe", "stripe_compatible"].includes(raw)) {
    return "signed_hmac";
  }
  return "signed_hmac";
}

function getLoopspaceWebhookAuthLabel(mode) {
  return normalizeLoopspaceWebhookAuthMode(mode) === "public_token" ? "Public URL" : "Signed";
}

function getForgeCanvasTintPalette(themeMode, spaceMode = getForgeSpaceMode()) {
  if (spaceMode === "loopspaces") {
    return themeMode === "light"
      ? {
        baseStroke: "rgba(181, 106, 0, 0.22)",
        centerStroke: "rgba(75, 46, 0, 0.08)",
        dot: "rgba(181, 106, 0, 0.22)",
        glow: "rgba(181, 106, 0, 0.28)",
        glowStart: "rgba(181, 106, 0, 0.14)",
        glowMid: "rgba(200, 128, 0, 0.2)",
        glowEnd: "rgba(221, 112, 31, 0.22)",
        strokeStart: "#8b5a00",
        strokeMid: "#c88000",
        strokeEnd: "#d8681b",
        warmDot: "rgba(221, 112, 31, 0.2)",
      }
      : {
        baseStroke: "rgba(255, 209, 102, 0.22)",
        centerStroke: "rgba(255, 244, 214, 0.08)",
        dot: "rgba(255, 209, 102, 0.26)",
        glow: "rgba(245, 158, 11, 0.34)",
        glowStart: "rgba(255, 209, 102, 0.18)",
        glowMid: "rgba(245, 158, 11, 0.28)",
        glowEnd: "rgba(240, 140, 69, 0.26)",
        strokeStart: "#fff0a5",
        strokeMid: "#ffd166",
        strokeEnd: "#f08c45",
        warmDot: "rgba(240, 140, 69, 0.24)",
      };
  }

  return themeMode === "light"
    ? {
      baseStroke: "rgba(0, 102, 204, 0.22)",
      centerStroke: "rgba(24, 34, 48, 0.08)",
      dot: "rgba(0, 102, 204, 0.24)",
      glow: "rgba(0, 102, 204, 0.3)",
      glowStart: "rgba(0, 102, 204, 0.14)",
      glowMid: "rgba(26, 140, 255, 0.22)",
      glowEnd: "rgba(221, 112, 31, 0.22)",
      strokeStart: "#005fb8",
      strokeMid: "#1a8cff",
      strokeEnd: "#d8681b",
      warmDot: "rgba(221, 112, 31, 0.2)",
    }
    : {
      baseStroke: "rgba(125, 176, 255, 0.2)",
      centerStroke: "rgba(230, 236, 245, 0.08)",
      dot: "rgba(155, 213, 255, 0.26)",
      glow: "rgba(125, 176, 255, 0.34)",
      glowStart: "rgba(158, 219, 255, 0.18)",
      glowMid: "rgba(74, 163, 255, 0.28)",
      glowEnd: "rgba(240, 140, 69, 0.26)",
      strokeStart: "#9edbff",
      strokeMid: "#4aa3ff",
      strokeEnd: "#f08c45",
      warmDot: "rgba(240, 140, 69, 0.22)",
    };
}

function drawOrchestratorVoiceDotField(context, tintPalette, alpha, phase) {
  const rings = [
    { count: 22, radius: 35.4, size: 0.42, speed: -0.09 },
    { count: 30, radius: 42.4, size: 0.5, speed: 0.07 },
    { count: 38, radius: 46.1, size: 0.44, speed: -0.045 },
  ];

  context.save();
  context.globalAlpha = alpha;

  rings.forEach((ring, ringIndex) => {
    for (let index = 0; index < ring.count; index += 1) {
      const angle = ((Math.PI * 2 * index) / ring.count) + (phase * ring.speed);
      const pulse = 0.66 + (Math.sin((phase * 1.8) + index * 0.72 + ringIndex) * 0.34);
      const point = getOrchestratorVoiceRingPoint(ring.radius, angle);

      context.beginPath();
      context.arc(point.x, point.y, ring.size * (0.75 + (pulse * 0.38)), 0, Math.PI * 2);
      context.fillStyle = index % 5 === 0 ? tintPalette.warmDot : tintPalette.dot;
      context.fill();
    }
  });

  context.restore();
}

function drawOrchestratorVoiceCanvasRing(context, waveform, options = {}) {
  const active = Boolean(options.active);
  const themeMode = options.themeMode === "light" ? "light" : "dark";
  const tintPalette = getForgeCanvasTintPalette(themeMode, options.spaceMode);
  const breath = active ? Math.min(1, Math.max(0, Number(options.breath || 0))) : 0;
  const phase = Number(options.phase || 0);
  const maxAmplitude = waveform.reduce(
    (maximum, value) => Math.max(maximum, Math.abs(Number(value || 0))),
    0,
  );
  const baseRadius = ORCHESTRATOR_VOICE_RING_BASE_RADIUS + (breath * 0.9);
  const waveLift = (ORCHESTRATOR_VOICE_RING_MAX_RADIUS - baseRadius) - 0.2;
  const waveformPoints = waveform.map((value, index) => {
    const angle = (-Math.PI / 2) + ((Math.PI * 2 * index) / ORCHESTRATOR_VOICE_WAVEFORM_POINT_COUNT);
    const connectedValue = getOrchestratorVoiceSmoothedEnvelopeValue(waveform, index);
    const shapedValue = Math.pow(Math.max(0, Math.min(1, Number(connectedValue || value || 0))), 0.78);
    const radius = Math.max(
      ORCHESTRATOR_VOICE_RING_MIN_RADIUS,
      Math.min(
        ORCHESTRATOR_VOICE_RING_MAX_RADIUS,
        baseRadius + (shapedValue * waveLift) + (breath * 0.32),
      ),
    );

    return getOrchestratorVoiceRingPoint(radius, angle);
  });
  const visibleAlpha = active || maxAmplitude > 0.01
    ? Math.min(1, 0.32 + (breath * 0.16) + (maxAmplitude * 0.48))
    : 0;
  const baseStroke = tintPalette.baseStroke;
  const centerStroke = tintPalette.centerStroke;
  const glow = tintPalette.glow;
  const strokeGradient = context.createLinearGradient(18, 10, 82, 90);
  const glowGradient = context.createLinearGradient(14, 16, 88, 84);

  strokeGradient.addColorStop(0, tintPalette.strokeStart);
  strokeGradient.addColorStop(0.5, tintPalette.strokeMid);
  strokeGradient.addColorStop(1, tintPalette.strokeEnd);
  glowGradient.addColorStop(0, tintPalette.glowStart);
  glowGradient.addColorStop(0.5, tintPalette.glowMid);
  glowGradient.addColorStop(1, tintPalette.glowEnd);

  context.clearRect(0, 0, 100, 100);

  if (visibleAlpha <= 0.01) {
    return;
  }

  context.save();
  context.globalAlpha = visibleAlpha;

  drawOrchestratorVoiceDotField(context, tintPalette, Math.min(0.42, 0.16 + (breath * 0.16)), phase);

  context.beginPath();
  context.arc(
    ORCHESTRATOR_VOICE_RING_CENTER,
    ORCHESTRATOR_VOICE_RING_CENTER,
    baseRadius,
    0,
    Math.PI * 2,
  );
  context.strokeStyle = baseStroke;
  context.lineWidth = 1.25;
  context.stroke();

  context.beginPath();
  context.arc(
    ORCHESTRATOR_VOICE_RING_CENTER,
    ORCHESTRATOR_VOICE_RING_CENTER,
    ORCHESTRATOR_VOICE_RING_MIN_RADIUS,
    0,
    Math.PI * 2,
  );
  context.strokeStyle = centerStroke;
  context.lineWidth = 0.9;
  context.stroke();

  context.save();
  context.globalAlpha *= 0.68;
  context.shadowBlur = 14;
  context.shadowColor = glow;
  context.beginPath();
  drawOrchestratorVoiceSmoothPath(context, waveformPoints);
  context.strokeStyle = glowGradient;
  context.lineWidth = 7.2;
  context.lineJoin = "round";
  context.lineCap = "round";
  context.stroke();
  context.restore();

  context.save();
  context.globalAlpha *= 0.74;
  context.beginPath();
  drawOrchestratorVoiceSmoothPath(context, waveformPoints);
  context.strokeStyle = themeMode === "light"
    ? "rgba(255, 255, 255, 0.56)"
    : "rgba(255, 255, 255, 0.24)";
  context.lineWidth = 4.6;
  context.stroke();
  context.restore();

  context.beginPath();
  drawOrchestratorVoiceSmoothPath(context, waveformPoints);
  context.strokeStyle = strokeGradient;
  context.lineWidth = 2.55;
  context.lineJoin = "round";
  context.lineCap = "round";
  context.stroke();

  context.restore();
}

