const TERMINAL_PANEL_ANCHOR_SELECTOR = "[data-terminal-panel-anchor='true']";
const TERMINAL_DOCUMENT_PANEL_ANCHOR_SELECTOR = "[data-terminal-document-panel-anchor='true']";

function releasePointerCaptureIfHeld(element, pointerId) {
  if (!element || pointerId === undefined || pointerId === null) {
    return;
  }

  try {
    if (element.hasPointerCapture?.(pointerId)) {
      element.releasePointerCapture?.(pointerId);
    }
  } catch {
    /* Pointer capture can already be gone after pointerup/cancel. */
  }
}

function isTerminalDocumentPanelPane(value) {
  return String(value || "") === TERMINAL_DOCUMENT_PANEL_ID;
}

function terminalPaneLayoutKey(value, { allowDocumentPanel = false, terminalIndexes = null } = {}) {
  if (allowDocumentPanel && isTerminalDocumentPanelPane(value)) {
    return TERMINAL_DOCUMENT_PANEL_ID;
  }

  const terminalIndex = Number.parseInt(value, 10);
  if (!Number.isInteger(terminalIndex) || terminalIndex < 0) {
    return null;
  }

  if (Array.isArray(terminalIndexes) && terminalIndexes.length && !terminalIndexes.includes(terminalIndex)) {
    return null;
  }

  return terminalIndex;
}

function terminalPaneLayoutKeyIdentity(value) {
  return isTerminalDocumentPanelPane(value) ? TERMINAL_DOCUMENT_PANEL_ID : String(value);
}

function terminalPaneLayoutDomIdPart(value) {
  return isTerminalDocumentPanelPane(value)
    ? "docs"
    : String(value).replace(/[^\w.-]/g, "_") || "pane";
}

function normalizeTerminalWorkspaceRootIdentity(rootPath) {
  return String(rootPath || "").trim().replace(/\\/g, "/").replace(/\/+$/g, "");
}

function getBalancedTerminalPaneRowValues(paneKeys) {
  const keys = Array.isArray(paneKeys) ? paneKeys.filter((paneKey) => paneKey !== null) : [];
  if (!keys.length) {
    return [];
  }

  const rowCount = Math.max(1, Math.ceil(keys.length / TERMINAL_GRID_MAX_BALANCED_COLUMNS));
  const baseRowSize = Math.floor(keys.length / rowCount);
  const largerRowCount = keys.length % rowCount;
  const rows = [];
  let keyCursor = 0;

  for (let rowIndex = 0; rowIndex < rowCount; rowIndex += 1) {
    const rowSize = baseRowSize + (rowIndex < largerRowCount ? 1 : 0);
    const rowKeys = keys.slice(keyCursor, keyCursor + rowSize);
    if (rowKeys.length) {
      rows.push(rowKeys);
    }
    keyCursor += rowSize;
  }

  return rows;
}

function shouldRebalanceTerminalPaneRowValues(rowValues) {
  const rows = Array.isArray(rowValues) ? rowValues.filter((row) => Array.isArray(row) && row.length) : [];
  return rows.some((row) => row.length > TERMINAL_GRID_MAX_BALANCED_COLUMNS);
}

function normalizeViewTerminalRows(rows, options = {}) {
  const {
    allowDocumentPanel = false,
    terminalIndexes: allowedTerminalIndexes = null,
  } = options;
  const usedIndexes = new Set();
  const normalizedRows = [];

  if (!Array.isArray(rows)) {
    return [];
  }

  rows.forEach((row) => {
    const rowIndexes = Array.isArray(row?.terminalIndexes)
      ? row.terminalIndexes
      : Array.isArray(row)
        ? row
        : [];
    const rowPaneKeys = [];

    rowIndexes.forEach((index) => {
      const paneKey = terminalPaneLayoutKey(index, {
        allowDocumentPanel,
        terminalIndexes: allowedTerminalIndexes,
      });
      const paneIdentity = terminalPaneLayoutKeyIdentity(paneKey);
      if (paneKey !== null && !usedIndexes.has(paneIdentity)) {
        usedIndexes.add(paneIdentity);
        rowPaneKeys.push(paneKey);
      }
    });

    if (rowPaneKeys.length) {
      normalizedRows.push({
        rowIndex: normalizedRows.length,
        terminalIndexes: rowPaneKeys,
      });
    }
  });

  return normalizedRows;
}

function cloneTerminalRows(rows, options = {}) {
  return normalizeViewTerminalRows(rows, options).map((row, rowIndex) => ({
    rowIndex,
    terminalIndexes: row.terminalIndexes.slice(),
  }));
}

function serializeTerminalRows(rows, options = {}) {
  return cloneTerminalRows(rows, options)
    .map((row) => row.terminalIndexes.join(","))
    .join("|");
}

function areTerminalRowsEqual(leftRows, rightRows, options = {}) {
  const left = cloneTerminalRows(leftRows, options);
  const right = cloneTerminalRows(rightRows, options);

  return left.length === right.length
    && left.every((leftRow, rowIndex) => (
      leftRow.terminalIndexes.length === right[rowIndex].terminalIndexes.length
      && leftRow.terminalIndexes.every((terminalIndex, columnIndex) => (
        terminalIndex === right[rowIndex].terminalIndexes[columnIndex]
      ))
    ));
}

function removeTerminalFromRows(rows, terminalIndex, options = {}) {
  const targetIdentity = terminalPaneLayoutKeyIdentity(terminalIndex);
  return cloneTerminalRows(rows, options)
    .map((row) => row.terminalIndexes.filter((index) => terminalPaneLayoutKeyIdentity(index) !== targetIdentity))
    .filter((terminalIndexes) => terminalIndexes.length)
    .map((terminalIndexes, rowIndex) => ({
      rowIndex,
      terminalIndexes,
    }));
}

function findTerminalRowPosition(rows, terminalIndex, options = {}) {
  const normalizedRows = cloneTerminalRows(rows, options);
  const targetIdentity = terminalPaneLayoutKeyIdentity(terminalIndex);

  for (let rowIndex = 0; rowIndex < normalizedRows.length; rowIndex += 1) {
    const columnIndex = normalizedRows[rowIndex].terminalIndexes.findIndex((index) => (
      terminalPaneLayoutKeyIdentity(index) === targetIdentity
    ));
    if (columnIndex >= 0) {
      return { rowIndex, columnIndex };
    }
  }

  return null;
}

function insertTerminalInRows(rows, terminalIndex, target, options = {}) {
  const paneKey = terminalPaneLayoutKey(terminalIndex, options);
  if (paneKey === null) {
    return cloneTerminalRows(rows, options);
  }

  const withoutTerminal = removeTerminalFromRows(rows, paneKey, options);

  if (!withoutTerminal.length) {
    return [{ rowIndex: 0, terminalIndexes: [paneKey] }];
  }

  const rowIndex = Math.max(0, Math.min(Number.parseInt(target?.rowIndex, 10) || 0, withoutTerminal.length));
  const nextRows = withoutTerminal.map((row) => row.terminalIndexes.slice());

  if (rowIndex >= nextRows.length) {
    nextRows.push([paneKey]);
  } else {
    const columnIndex = Math.max(
      0,
      Math.min(Number.parseInt(target?.columnIndex, 10) || 0, nextRows[rowIndex].length),
    );
    nextRows[rowIndex].splice(columnIndex, 0, paneKey);
  }

  return nextRows
    .filter((terminalIndexes) => terminalIndexes.length)
    .map((terminalIndexes, nextRowIndex) => ({
      rowIndex: nextRowIndex,
      terminalIndexes,
    }));
}

function getTerminalRowsWithoutDocumentPanel(rows) {
  return cloneTerminalRows(rows, { allowDocumentPanel: true })
    .map((row) => row.terminalIndexes.filter((paneKey) => Number.isInteger(paneKey)))
    .filter((terminalIndexes) => terminalIndexes.length)
    .map((terminalIndexes, rowIndex) => ({
      rowIndex,
      terminalIndexes,
    }));
}

function reconcileDocumentPanelRows({
  currentRows = null,
  documentPanelAvailable = false,
  terminalIndexes = [],
  terminalRows = [],
} = {}) {
  const baseRows = cloneTerminalRows(terminalRows, { terminalIndexes });
  if (!documentPanelAvailable) {
    return baseRows;
  }

  const currentPanelRows = cloneTerminalRows(currentRows, {
    allowDocumentPanel: true,
    terminalIndexes,
  });

  if (!currentPanelRows.some((row) => row.terminalIndexes.includes(TERMINAL_DOCUMENT_PANEL_ID))) {
    return getBalancedTerminalPaneRowValues([
      TERMINAL_DOCUMENT_PANEL_ID,
      ...baseRows.flatMap((row) => row.terminalIndexes),
    ]).map((terminalIndexes, rowIndex) => ({
      rowIndex,
      terminalIndexes,
    }));
  }

  const logicalIndexSet = new Set(terminalIndexes);
  const usedTerminalIndexes = new Set();
  let documentIncluded = false;
  const nextRows = currentPanelRows
    .map((row) => {
      const rowIndexes = [];
      row.terminalIndexes.forEach((paneKey) => {
        if (isTerminalDocumentPanelPane(paneKey)) {
          if (!documentIncluded) {
            documentIncluded = true;
            rowIndexes.push(TERMINAL_DOCUMENT_PANEL_ID);
          }
          return;
        }
        if (
          Number.isInteger(paneKey)
          && logicalIndexSet.has(paneKey)
          && !usedTerminalIndexes.has(paneKey)
        ) {
          usedTerminalIndexes.add(paneKey);
          rowIndexes.push(paneKey);
        }
      });
      return rowIndexes;
    })
    .filter((rowIndexes) => rowIndexes.length);

  if (!documentIncluded) {
    if (nextRows.length) {
      nextRows[0].unshift(TERMINAL_DOCUMENT_PANEL_ID);
    } else {
      nextRows.push([TERMINAL_DOCUMENT_PANEL_ID]);
    }
  }

  baseRows.forEach((row) => {
    const missingTerminalIndexes = row.terminalIndexes.filter((terminalIndex) => (
      !usedTerminalIndexes.has(terminalIndex)
    ));
    if (missingTerminalIndexes.length) {
      nextRows.push(missingTerminalIndexes);
    }
  });

  const displayRows = shouldRebalanceTerminalPaneRowValues(nextRows)
    ? getBalancedTerminalPaneRowValues(nextRows.flat())
    : nextRows;

  return displayRows.map((terminalIndexes, rowIndex) => ({
    rowIndex,
    terminalIndexes,
  }));
}

function getAbsoluteRect(relativeRect, containerRect) {
  if (!relativeRect || !containerRect) {
    return null;
  }

  return {
    bottom: containerRect.top + relativeRect.top + relativeRect.height,
    height: relativeRect.height,
    left: containerRect.left + relativeRect.left,
    right: containerRect.left + relativeRect.left + relativeRect.width,
    top: containerRect.top + relativeRect.top,
    width: relativeRect.width,
  };
}

function pointIsInRect(clientX, clientY, rect) {
  return rect
    && clientX >= rect.left
    && clientX <= rect.right
    && clientY >= rect.top
    && clientY <= rect.bottom;
}

function getPlainDomRect(rect) {
  if (!rect) {
    return null;
  }

  return {
    height: Number(rect.height || 0),
    left: Number(rect.left || 0),
    top: Number(rect.top || 0),
    width: Number(rect.width || 0),
  };
}

function getTodoDropTargetFromPoint({
  clientX,
  clientY,
  containerRect,
  fullscreenTerminalIndex,
  rects,
  terminalIndexes,
}) {
  if (
    Number.isInteger(fullscreenTerminalIndex)
    && pointIsInRect(clientX, clientY, containerRect)
  ) {
    return fullscreenTerminalIndex;
  }

  for (const terminalIndex of terminalIndexes || []) {
    const rect = getAbsoluteRect(rects?.[terminalIndex], containerRect);
    if (pointIsInRect(clientX, clientY, rect)) {
      return terminalIndex;
    }
  }

  return null;
}

function dataTransferHasType(dataTransfer, type) {
  return Array.from(dataTransfer?.types || []).includes(type);
}

function getJsonDragPayload(dataTransfer, type) {
  const raw = String(dataTransfer?.getData?.(type) || "").trim();
  if (!raw) {
    return null;
  }

  try {
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch {
    return null;
  }
}

function getDraggedWorkspaceToolTodoDrop(dataTransfer) {
  const payload = getJsonDragPayload(dataTransfer, WORKSPACE_TOOL_TODO_DRAG_MIME);
  const text = normalizeTodoQueueText(payload?.text);
  if (!text) {
    return null;
  }
  const sendFlag = payload?.send_on_drop ?? payload?.sendOnDrop ?? payload?.send;
  return {
    send: sendFlag === undefined ? true : Boolean(sendFlag),
    text,
  };
}

function getDraggedArchitectureGraphTodoText(dataTransfer) {
  const payload = getJsonDragPayload(dataTransfer, ARCHITECTURE_GRAPH_DRAG_MIME);
  const graphId = String(payload?.graphId || payload?.graph_id || "").trim();
  if (!graphId) {
    return "";
  }

  const title = String(payload?.title || payload?.name || graphId).trim();
  const filePath = String(payload?.filePath || payload?.file_path || `.agents/architectures/graphs/${graphId}.arch`).trim();
  const sourceRepoPath = String(payload?.sourceRepoPath || payload?.source_repo_path || "").trim();
  const sourceSuffix = sourceRepoPath ? ` in ${sourceRepoPath}` : "";
  return normalizeTodoQueueText(
    `Use the architecture graph "${title}" at ${filePath}${sourceSuffix} as the working context for this task.`,
  );
}

function getTerminalNativeTodoDrop(dataTransfer) {
  const workspaceToolDrop = getDraggedWorkspaceToolTodoDrop(dataTransfer);
  if (workspaceToolDrop?.text) {
    return workspaceToolDrop;
  }
  const architectureText = getDraggedArchitectureGraphTodoText(dataTransfer);
  return architectureText ? { send: true, text: architectureText } : null;
}

function isTerminalNativeTodoDropTransfer(dataTransfer) {
  return dataTransferHasType(dataTransfer, WORKSPACE_TOOL_TODO_DRAG_MIME)
    || dataTransferHasType(dataTransfer, ARCHITECTURE_GRAPH_DRAG_MIME);
}

function getTerminalSurfaceSlotIndexFromPoint(clientX, clientY, terminalIndexes) {
  if (typeof document === "undefined" || typeof document.elementFromPoint !== "function") {
    return null;
  }

  const element = document.elementFromPoint(clientX, clientY);
  const slot = element?.closest?.("[data-terminal-surface-slot='true']");
  const terminalIndex = Number.parseInt(slot?.getAttribute?.("data-terminal-index") || "", 10);

  return Number.isInteger(terminalIndex) && (terminalIndexes || []).includes(terminalIndex)
    ? terminalIndex
    : null;
}

function getRowsWithMetrics(rows, rects, containerRect, draggedTerminalIndex, options = {}) {
  const draggedIdentity = terminalPaneLayoutKeyIdentity(draggedTerminalIndex);
  return cloneTerminalRows(rows, options)
    .map((row, rowIndex) => {
      const rowRects = row.terminalIndexes
        .filter((terminalIndex) => terminalPaneLayoutKeyIdentity(terminalIndex) !== draggedIdentity)
        .map((terminalIndex) => ({
          rect: getAbsoluteRect(rects[terminalIndex], containerRect),
          terminalIndex,
        }))
        .filter((entry) => entry.rect);

      if (!rowRects.length) {
        return null;
      }

      return {
        bottom: Math.max(...rowRects.map((entry) => entry.rect.bottom)),
        left: Math.min(...rowRects.map((entry) => entry.rect.left)),
        rects: rowRects,
        right: Math.max(...rowRects.map((entry) => entry.rect.right)),
        rowIndex,
        top: Math.min(...rowRects.map((entry) => entry.rect.top)),
      };
    })
    .filter(Boolean);
}

function getDragTargetFromPoint({
  clientX,
  clientY,
  containerRect,
  draggedTerminalIndex,
  includeDocumentPanel = false,
  rects,
  rows,
}) {
  const rowOptions = { allowDocumentPanel: includeDocumentPanel };
  const draggedIdentity = terminalPaneLayoutKeyIdentity(draggedTerminalIndex);
  const normalizedRows = cloneTerminalRows(rows, rowOptions);
  const rowMetrics = getRowsWithMetrics(
    normalizedRows,
    rects,
    containerRect,
    draggedTerminalIndex,
    rowOptions,
  );

  for (const row of normalizedRows) {
    for (const terminalIndex of row.terminalIndexes) {
      if (terminalPaneLayoutKeyIdentity(terminalIndex) === draggedIdentity) {
        continue;
      }

      const rect = getAbsoluteRect(rects[terminalIndex], containerRect);
      if (!pointIsInRect(clientX, clientY, rect)) {
        continue;
      }

      const position = findTerminalRowPosition(normalizedRows, terminalIndex, rowOptions);
      if (!position) {
        continue;
      }

      return {
        columnIndex: position.columnIndex + (clientX >= rect.left + rect.width / 2 ? 1 : 0),
        rowIndex: position.rowIndex,
      };
    }
  }

  if (!rowMetrics.length) {
    return { columnIndex: 0, rowIndex: 0 };
  }

  const firstRow = rowMetrics[0];
  const lastRow = rowMetrics[rowMetrics.length - 1];

  if (clientY < firstRow.top) {
    return { columnIndex: 0, rowIndex: 0 };
  }

  if (clientY > lastRow.bottom) {
    return { columnIndex: 0, rowIndex: normalizedRows.length };
  }

  const nearestRow = rowMetrics.reduce((bestRow, row) => {
    if (clientY >= row.top && clientY <= row.bottom) {
      return row;
    }

    const rowCenter = row.top + (row.bottom - row.top) / 2;
    const bestCenter = bestRow.top + (bestRow.bottom - bestRow.top) / 2;
    return Math.abs(clientY - rowCenter) < Math.abs(clientY - bestCenter) ? row : bestRow;
  }, rowMetrics[0]);

  const sortedRects = nearestRow.rects
    .slice()
    .sort((left, right) => left.rect.left - right.rect.left);
  const beforeIndex = sortedRects.findIndex((entry) => clientX < entry.rect.left + entry.rect.width / 2);
  const targetTerminalIndex = beforeIndex >= 0
    ? sortedRects[beforeIndex].terminalIndex
    : sortedRects[sortedRects.length - 1].terminalIndex;
  const position = findTerminalRowPosition(normalizedRows, targetTerminalIndex, rowOptions);

  if (!position) {
    return {
      columnIndex: normalizedRows[nearestRow.rowIndex]?.terminalIndexes.length || 0,
      rowIndex: nearestRow.rowIndex,
    };
  }

  return {
    columnIndex: beforeIndex >= 0 ? position.columnIndex : position.columnIndex + 1,
    rowIndex: position.rowIndex,
  };
}

function areRectMapsEqual(left, right) {
  const leftKeys = Object.keys(left || {});
  const rightKeys = Object.keys(right || {});

  return leftKeys.length === rightKeys.length
    && leftKeys.every((key) => {
      const leftRect = left[key];
      const rightRect = right[key];
      return rightRect
        && Math.abs(leftRect.left - rightRect.left) < 0.5
        && Math.abs(leftRect.top - rightRect.top) < 0.5
        && Math.abs(leftRect.width - rightRect.width) < 0.5
        && Math.abs(leftRect.height - rightRect.height) < 0.5;
    });
}

function areRectsEqual(leftRect, rightRect) {
  if (!leftRect || !rightRect) {
    return leftRect === rightRect;
  }

  return Math.abs(leftRect.left - rightRect.left) < 0.5
    && Math.abs(leftRect.top - rightRect.top) < 0.5
    && Math.abs(leftRect.width - rightRect.width) < 0.5
    && Math.abs(leftRect.height - rightRect.height) < 0.5;
}

function getTerminalBreakoutStorageKey(workspaceId) {
  const safeWorkspaceId = String(workspaceId || "default")
    .replace(/[^\w.-]/g, "_")
    .slice(0, 120) || "default";

  return `${TERMINAL_BREAKOUT_STORAGE_PREFIX}.${safeWorkspaceId}`;
}

function clampBreakoutZoom(value) {
  const zoom = Number(value);

  if (!Number.isFinite(zoom)) {
    return TERMINAL_BREAKOUT_DEFAULT_ZOOM;
  }

  return Math.max(TERMINAL_BREAKOUT_MIN_ZOOM, Math.min(TERMINAL_BREAKOUT_MAX_ZOOM, zoom));
}

function clampBreakoutTerminalScale(value) {
  const scale = Number(value);

  if (!Number.isFinite(scale)) {
    return TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE;
  }

  return Math.max(
    TERMINAL_BREAKOUT_MIN_TERMINAL_SCALE,
    Math.min(TERMINAL_BREAKOUT_MAX_TERMINAL_SCALE, scale),
  );
}

function normalizeBreakoutViewport(value) {
  const x = Number(value?.x || 0);
  const y = Number(value?.y || 0);
  const zoom = clampBreakoutZoom(value?.zoom);

  return {
    x: Number.isFinite(x) ? x : 0,
    y: Number.isFinite(y) ? y : 0,
    zoom,
  };
}

function isTerminalBreakoutHoldDragExcludedTarget(target) {
  return Boolean(target?.closest?.(
    "[data-terminal-control='true'], [data-terminal-drag-handle='true'], [data-terminal-resize-handle='true'], button, input, textarea, select, a, [contenteditable='true']",
  ));
}

function normalizeBreakoutPlacement(value) {
  const x = Number(value?.x);
  const y = Number(value?.y);
  const width = Number(value?.width);
  const height = Number(value?.height);
  const z = Number.parseInt(value?.z, 10);

  if (
    !Number.isFinite(x)
    || !Number.isFinite(y)
    || !Number.isFinite(width)
    || !Number.isFinite(height)
    || width <= 0
    || height <= 0
  ) {
    return null;
  }

  return {
    height,
    width,
    x,
    y,
    z: Number.isInteger(z) ? z : 1,
  };
}

function normalizeBreakoutPlacements(value, terminalIndexes = []) {
  const terminalIndexSet = new Set((terminalIndexes || [])
    .filter((terminalIndex) => Number.isInteger(terminalIndex)));
  const source = value && typeof value === "object" ? value : {};
  const placements = {};

  Object.keys(source).forEach((key) => {
    const terminalIndex = Number.parseInt(key, 10);
    if (!Number.isInteger(terminalIndex) || (terminalIndexSet.size && !terminalIndexSet.has(terminalIndex))) {
      return;
    }

    const placement = normalizeBreakoutPlacement(source[key]);
    if (placement) {
      placements[terminalIndex] = placement;
    }
  });

  return placements;
}

function canUseBrowserLocalStorage() {
  try {
    return typeof window !== "undefined" && typeof window.localStorage !== "undefined";
  } catch {
    return false;
  }
}

function readTerminalBreakoutLayout(storageKey, terminalIndexes = []) {
  if (!canUseBrowserLocalStorage()) {
    return {
      placements: {},
      terminalScale: TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE,
      viewport: TERMINAL_BREAKOUT_DEFAULT_VIEWPORT,
    };
  }

  try {
    const parsed = JSON.parse(window.localStorage.getItem(storageKey) || "{}");
    return {
      placements: normalizeBreakoutPlacements(parsed?.placements, terminalIndexes),
      terminalScale: clampBreakoutTerminalScale(parsed?.terminalScale),
      viewport: normalizeBreakoutViewport(parsed?.viewport),
    };
  } catch {
    return {
      placements: {},
      terminalScale: TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE,
      viewport: TERMINAL_BREAKOUT_DEFAULT_VIEWPORT,
    };
  }
}

function writeTerminalBreakoutLayout(storageKey, layout) {
  if (!canUseBrowserLocalStorage()) {
    return;
  }

  try {
    window.localStorage.setItem(storageKey, JSON.stringify({
      placements: normalizeBreakoutPlacements(layout?.placements),
      terminalScale: clampBreakoutTerminalScale(layout?.terminalScale),
      viewport: normalizeBreakoutViewport(layout?.viewport),
    }));
  } catch {
    // Breakout layout is a visual preference; storage failures should not block terminals.
  }
}

function terminalBreakoutPlanData(response) {
  return response?.data || response || {};
}

function cleanTerminalBreakoutPlanText(value) {
  return String(value || "").trim();
}

function terminalBreakoutPlanPathIdentity(value) {
  const cleaned = cleanTerminalBreakoutPlanText(value).replace(/\\/g, "/");
  return cleaned === "/" ? cleaned : cleaned.replace(/\/+$/g, "").toLowerCase();
}

function terminalBreakoutPlanCacheKey({
  agentId = "",
  dbPath = "",
  repoPath = "",
  sessionId = "",
  taskId = "",
  workspaceId = "",
} = {}) {
  const repoIdentity = terminalBreakoutPlanPathIdentity(repoPath);
  const planIdentity = cleanTerminalBreakoutPlanText(taskId)
    || cleanTerminalBreakoutPlanText(sessionId);
  if (!repoIdentity || !planIdentity) {
    return "";
  }

  return [
    cleanTerminalBreakoutPlanText(workspaceId),
    repoIdentity,
    terminalBreakoutPlanPathIdentity(dbPath),
    cleanTerminalBreakoutPlanText(taskId),
    cleanTerminalBreakoutPlanText(sessionId),
    cleanTerminalBreakoutPlanText(agentId),
  ].join("|");
}

function trimTerminalBreakoutPlanCache() {
  while (terminalBreakoutPlanCache.size > TERMINAL_BREAKOUT_PLAN_CACHE_LIMIT) {
    const oldestKey = terminalBreakoutPlanCache.keys().next().value;
    if (!oldestKey) {
      return;
    }
    terminalBreakoutPlanCache.delete(oldestKey);
  }
}

function cacheTerminalBreakoutPlanSnapshot(cacheKey, snapshot) {
  if (!cacheKey || !snapshot || typeof snapshot !== "object") {
    return;
  }

  terminalBreakoutPlanCache.delete(cacheKey);
  terminalBreakoutPlanCache.set(cacheKey, {
    snapshot,
    updatedAt: Date.now(),
  });
  trimTerminalBreakoutPlanCache();
}

function cachedTerminalBreakoutPlanSnapshot(cacheKey, { freshOnly = false } = {}) {
  if (!cacheKey) {
    return null;
  }

  const entry = terminalBreakoutPlanCache.get(cacheKey);
  if (!entry?.snapshot) {
    return null;
  }

  if (
    freshOnly
    && Date.now() - Number(entry.updatedAt || 0) > TERMINAL_BREAKOUT_PLAN_CACHE_FRESH_MS
  ) {
    return null;
  }

  return entry.snapshot;
}

function trimTerminalBreakoutActivityCache() {
  while (terminalBreakoutActivityCache.size > TERMINAL_BREAKOUT_ACTIVITY_CACHE_LIMIT) {
    const oldestKey = terminalBreakoutActivityCache.keys().next().value;
    if (!oldestKey) {
      return;
    }
    terminalBreakoutActivityCache.delete(oldestKey);
  }
}

function createTerminalBreakoutActivityEntry(paneId, snapshot, error = "") {
  const message = String(error || "");
  return {
    error: message,
    signature: message ? `error:${message}` : JSON.stringify(snapshot || null),
    snapshot: message ? null : snapshot,
    updatedAt: Date.now(),
    paneId,
  };
}

function cacheTerminalBreakoutActivityEntry(paneId, entry) {
  if (!paneId || !entry) {
    return;
  }

  terminalBreakoutActivityCache.delete(paneId);
  terminalBreakoutActivityCache.set(paneId, entry);
  trimTerminalBreakoutActivityCache();
}

function cachedTerminalBreakoutActivityEntry(paneId, { freshOnly = false } = {}) {
  if (!paneId) {
    return null;
  }

  const entry = terminalBreakoutActivityCache.get(paneId);
  if (!entry) {
    return null;
  }

  if (
    freshOnly
    && Date.now() - Number(entry.updatedAt || 0) > TERMINAL_BREAKOUT_ACTIVITY_CACHE_FRESH_MS
  ) {
    return null;
  }

  return entry;
}

function requestTerminalBreakoutActivitySnapshot(paneId, { force = false } = {}) {
  const safePaneId = cleanTerminalBreakoutPlanText(paneId);
  if (!safePaneId) {
    return Promise.resolve(createTerminalBreakoutActivityEntry("", null));
  }

  if (!force) {
    const freshEntry = cachedTerminalBreakoutActivityEntry(safePaneId, { freshOnly: true });
    if (freshEntry) {
      return Promise.resolve(freshEntry);
    }
  }

  const existingRequest = terminalBreakoutActivityRequests.get(safePaneId);
  if (existingRequest) {
    return existingRequest;
  }

  const request = invoke("terminal_activity_snapshot", { paneId: safePaneId })
    .then((snapshot) => {
      const entry = createTerminalBreakoutActivityEntry(safePaneId, snapshot);
      cacheTerminalBreakoutActivityEntry(safePaneId, entry);
      return entry;
    })
    .catch((error) => {
      const entry = createTerminalBreakoutActivityEntry(safePaneId, null, getErrorMessage(error));
      cacheTerminalBreakoutActivityEntry(safePaneId, entry);
      return entry;
    })
    .finally(() => {
      terminalBreakoutActivityRequests.delete(safePaneId);
    });

  terminalBreakoutActivityRequests.set(safePaneId, request);
  return request;
}

function normalizeTerminalBreakoutPlanStatus(status) {
  const normalized = cleanTerminalBreakoutPlanText(status).toLowerCase();
  if (["done", "complete", "completed", "finished", "success"].includes(normalized)) {
    return "completed";
  }
  if (["interrupt", "interrupted", "cancelled", "canceled", "stopped"].includes(normalized)) {
    return "interrupted";
  }
  if (normalized === "blocked") {
    return "blocked";
  }
  return "active";
}

function terminalBreakoutPlanIsLive(plan) {
  const status = normalizeTerminalBreakoutPlanStatus(plan?.status);
  return status === "active" || status === "blocked";
}

function terminalBreakoutPlanStatusLabel(status) {
  return normalizeTerminalBreakoutPlanStatus(status) === "blocked" ? "Blocked" : "Active";
}

function getLiveTerminalBreakoutPlan(snapshot) {
  const data = terminalBreakoutPlanData(snapshot);
  const selectedPlan = data?.selected_plan || data?.selectedPlan || null;
  return terminalBreakoutPlanIsLive(selectedPlan) ? selectedPlan : null;
}

function terminalBreakoutPlanStepStatusKind(status) {
  const normalized = cleanTerminalBreakoutPlanText(status).toLowerCase();
  if (["done", "complete", "completed", "finished", "success"].includes(normalized)) {
    return "completed";
  }
  if ([
    "active",
    "current",
    "in_progress",
    "in-progress",
    "pending",
    "running",
    "working",
  ].includes(normalized)) {
    return "active";
  }
  if (normalized === "blocked" || normalized === "interrupted") {
    return "blocked";
  }
  if (normalized === "skipped") {
    return "skipped";
  }
  return "queued";
}

function terminalBreakoutPlanTitle(plan) {
  return cleanTerminalBreakoutPlanText(plan?.title || plan?.task_title || plan?.taskTitle)
    || "Live plan";
}

function terminalBreakoutPlanSteps(plan) {
  return Array.isArray(plan?.steps) ? plan.steps : [];
}

function terminalActivityArray(value) {
  return Array.isArray(value) ? value : [];
}

function terminalBreakoutActivityProcesses(snapshot) {
  const seen = new Set();
  return [
    ...terminalActivityArray(snapshot?.devServers),
    ...terminalActivityArray(snapshot?.processes),
  ].filter((process) => {
    const pid = Number(process?.pid || 0);
    if (!Number.isInteger(pid) || pid <= 0 || seen.has(pid)) {
      return false;
    }
    seen.add(pid);
    return true;
  });
}

function terminalBreakoutActivityHasContent(snapshot) {
  return terminalActivityArray(snapshot?.subagents).length > 0
    || terminalBreakoutActivityProcesses(snapshot).length > 0;
}

function formatTerminalActivityBytes(value) {
  const bytes = Number(value || 0);
  if (!Number.isFinite(bytes) || bytes <= 0) {
    return "";
  }
  const units = ["B", "KB", "MB", "GB", "TB"];
  let unitIndex = 0;
  let amount = bytes;
  while (amount >= 1024 && unitIndex < units.length - 1) {
    amount /= 1024;
    unitIndex += 1;
  }
  const precision = amount >= 10 || unitIndex === 0 ? 0 : 1;
  return `${amount.toFixed(precision)} ${units[unitIndex]}`;
}

function formatTerminalActivityCpu(value) {
  const cpu = Number(value || 0);
  if (!Number.isFinite(cpu) || cpu <= 0) {
    return "";
  }
  return cpu >= 10 ? `${Math.round(cpu)}% CPU` : `${cpu.toFixed(1)}% CPU`;
}

function formatTerminalActivityDuration(seconds) {
  const totalSeconds = Math.max(0, Math.floor(Number(seconds || 0)));
  if (!Number.isFinite(totalSeconds) || totalSeconds <= 0) {
    return "";
  }
  if (totalSeconds < 60) {
    return `${totalSeconds}s`;
  }
  const minutes = Math.floor(totalSeconds / 60);
  if (minutes < 60) {
    return `${minutes}m`;
  }
  const hours = Math.floor(minutes / 60);
  const remainder = minutes % 60;
  return remainder ? `${hours}h ${remainder}m` : `${hours}h`;
}

function terminalActivityBoundPorts(process) {
  return Array.isArray(process?.boundPorts) ? process.boundPorts : [];
}

function terminalActivityPortLabel(process) {
  const ports = terminalActivityBoundPorts(process);
  if (!ports.length) {
    return "";
  }
  const first = ports[0];
  const suffix = ports.length > 1 ? ` +${ports.length - 1}` : "";
  return `:${first.port}${suffix}`;
}

function terminalActivityProcessLabel(process) {
  const command = String(process?.command || "").trim();
  const name = String(process?.name || process?.displayName || process?.groupLabel || "").trim();
  const compact = command.replace(/\s+/g, " ");
  if (command) {
    const lower = compact.toLowerCase();
    const known = [
      "npm run dev",
      "npm start",
      "pnpm dev",
      "pnpm run dev",
      "yarn dev",
      "yarn start",
      "bun dev",
      "vite",
      "next dev",
      "astro dev",
      "nuxt dev",
      "python -m http.server",
      "python3 -m http.server",
      "cargo run",
      "tauri dev",
    ].find((needle) => lower.includes(needle));
    if (known) {
      return known;
    }
  }
  if (name) {
    return name.length > 36 ? `${name.slice(0, 33)}...` : name;
  }
  if (command) {
    const leaf = compact.split(/[\\/]/).filter(Boolean).pop() || compact;
    return leaf.length > 36 ? `${leaf.slice(0, 33)}...` : leaf;
  }
  return process?.pid ? `process ${process.pid}` : "process";
}

function terminalActivitySubagentName(subagent) {
  return cleanTerminalBreakoutPlanText(subagent?.label || subagent?.agentType || subagent?.agentId)
    || "Subagent";
}

// Per-agent glyph hue, stable across snapshots: hash the display name into a
// small palette so "Ampere" stays purple and "Ohm" stays orange the whole
// session, like the reference monitor UI.
const TERMINAL_ACTIVITY_GLYPH_COLORS = [
  "#a78bfa",
  "#fb923c",
  "#facc15",
  "#34d399",
  "#60a5fa",
  "#f472b6",
];

function terminalActivityGlyphColor(name) {
  const text = String(name || "");
  let hash = 0;
  for (let index = 0; index < text.length; index += 1) {
    hash = ((hash * 31) + text.charCodeAt(index)) >>> 0;
  }
  return TERMINAL_ACTIVITY_GLYPH_COLORS[hash % TERMINAL_ACTIVITY_GLYPH_COLORS.length];
}

function terminalActivityStatusKey(value) {
  return cleanTerminalBreakoutPlanText(value).toLowerCase().replace(/[\s_]+/g, "-");
}

function terminalBreakoutActivityStatusKind(value) {
  const status = terminalActivityStatusKey(value);
  if ([
    "awaiting-approval",
    "awaiting-input",
    "awaiting-instruction",
    "awaiting-user",
    "blocked",
    "needs-user",
    "needs-user-input",
    "paused",
    "requires-input",
    "requires-user-input",
    "waiting",
    "waiting-for-user",
  ].includes(status)) {
    return "awaiting";
  }
  if (["done", "complete", "completed", "finished", "success"].includes(status)) {
    return "done";
  }
  if (["cancelled", "canceled", "error", "failed", "interrupted", "stopped"].includes(status)) {
    return "failed";
  }
  return "running";
}

function terminalBreakoutActivityStatusLabel(value) {
  const statusKind = terminalBreakoutActivityStatusKind(value);
  if (statusKind === "awaiting") return "awaiting instruction";
  if (statusKind === "done") return "finished";
  if (statusKind === "failed") return "needs review";
  return "running";
}

function terminalBreakoutActivityRowKey(paneId, kind, id) {
  return `${paneId || "pane"}:${kind}:${cleanTerminalBreakoutPlanText(id) || "item"}`;
}

function terminalBreakoutActivityDetailPairs(pairs) {
  return pairs
    .map(([label, value]) => [label, cleanTerminalBreakoutPlanText(value)])
    .filter(([, value]) => Boolean(value));
}

function terminalActivitySubagentTitle(subagent) {
  return `${terminalActivitySubagentName(subagent)} is ${terminalBreakoutActivityStatusLabel(subagent?.status)}`;
}

function terminalActivitySubagentDetails(subagent) {
  return terminalBreakoutActivityDetailPairs([
    ["Status", terminalBreakoutActivityStatusLabel(subagent?.status)],
    ["Provider", subagent?.provider],
    ["Type", subagent?.agentType],
    ["Agent", subagent?.agentId],
    ["Source", subagent?.source],
    ["Prompt", subagent?.description],
    ["Last", subagent?.lastMessage],
    ["Transcript", subagent?.agentTranscriptPath || subagent?.transcriptPath],
  ]);
}

function terminalActivityProcessDetails(process) {
  return terminalBreakoutActivityDetailPairs([
    ["PID", process?.pid],
    ["CPU", formatTerminalActivityCpu(process?.cpuPercent)],
    ["Memory", formatTerminalActivityBytes(process?.memoryBytes)],
    ["Runtime", formatTerminalActivityDuration(process?.runTimeSeconds)],
    ["Ports", terminalActivityPortLabel(process)],
    ["Children", process?.childCount ? `${process.childCount}` : ""],
    ["CWD", process?.cwd],
    ["Command", process?.command || process?.executable],
  ]);
}

function terminalArchitectureObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : null;
}

function terminalArchitectureRemoteCommand(item) {
  return terminalArchitectureObject(item?.remoteCommand)
    || terminalArchitectureObject(item?.remote_command)
    || {};
}

function terminalArchitectureRunFromItem(item) {
  const remoteCommand = terminalArchitectureRemoteCommand(item);
  return terminalArchitectureObject(item?.architectureRun)
    || terminalArchitectureObject(item?.architecture_run)
    || terminalArchitectureObject(remoteCommand.architectureRun)
    || terminalArchitectureObject(remoteCommand.architecture_run)
    || null;
}

function terminalArchitectureGraphIdentity(graph, fallback = {}) {
  const rawGraph = terminalArchitectureObject(graph);
  if (!rawGraph) {
    return null;
  }

  const title = cleanTerminalBreakoutPlanText(
    rawGraph.title
      || rawGraph.name
      || rawGraph.label
      || rawGraph.graphTitle
      || rawGraph.graph_title
      || fallback.title,
  );
  const filePath = cleanTerminalBreakoutPlanText(
    rawGraph.filePath
      || rawGraph.file_path
      || rawGraph.path
      || rawGraph.graphFilePath
      || rawGraph.graph_file_path
      || fallback.filePath,
  );
  const id = cleanTerminalBreakoutPlanText(
    rawGraph.id
      || rawGraph.graphId
      || rawGraph.graph_id
      || rawGraph.architectureId
      || rawGraph.architecture_id
      || fallback.id,
  );
  const repoPath = cleanTerminalBreakoutPlanText(
    rawGraph.repoPath
      || rawGraph.repo_path
      || fallback.repoPath,
  );
  const graphKey = cleanTerminalBreakoutPlanText(
    rawGraph.graphKey
      || rawGraph.graph_key
      || fallback.graphKey,
  );

  if (!title && !filePath && !id && !graphKey) {
    return null;
  }

  return {
    filePath,
    graphKey,
    id,
    repoPath,
    title: title || filePath.split(/[\\/]/).filter(Boolean).pop() || "Architecture",
  };
}

function terminalArchitectureGraphFromItem(item) {
  const remoteCommand = terminalArchitectureRemoteCommand(item);
  return terminalArchitectureGraphIdentity(
    item?.architectureGraph
      || item?.architecture_graph
      || remoteCommand.architectureGraph
      || remoteCommand.architecture_graph
      || {
        filePath: remoteCommand.graphFilePath || remoteCommand.graph_file_path,
        id: remoteCommand.graphId || remoteCommand.graph_id,
        repoPath: remoteCommand.repoPath || remoteCommand.repo_path,
        title: remoteCommand.graphTitle || remoteCommand.graph_title,
      },
  );
}

function terminalArchitectureGraphFromSnapshot(snapshot) {
  const body = terminalArchitectureObject(snapshot?.graph)
    || terminalArchitectureObject(snapshot?.data?.graph)
    || terminalArchitectureObject(snapshot?.snapshot?.graph)
    || terminalArchitectureObject(snapshot);
  return terminalArchitectureGraphIdentity(body, {
    repoPath: snapshot?.repoPath || snapshot?.repo_path,
  });
}

function terminalArchitectureSelectedGraphFromState(state) {
  const graphState = terminalArchitectureObject(state);
  if (!graphState) {
    return null;
  }

  const selectedGraphId = cleanTerminalBreakoutPlanText(graphState.architectureSelectedGraphId);
  const selectedRepoPath = cleanTerminalBreakoutPlanText(graphState.architectureSelectedRepoPath || graphState.repoPath);
  const selectedRepoKey = terminalBreakoutPlanPathIdentity(selectedRepoPath);
  const lists = terminalArchitectureObject(graphState.architectureGraphLists) || {};
  const entries = Object.entries(lists);
  const preferredEntry = entries.find(([repoKey, entry]) => (
    terminalBreakoutPlanPathIdentity(repoKey) === selectedRepoKey
      || terminalBreakoutPlanPathIdentity(entry?.repoPath || entry?.repo_path) === selectedRepoKey
  ));
  const orderedEntries = preferredEntry
    ? [preferredEntry, ...entries.filter(([repoKey]) => repoKey !== preferredEntry[0])]
    : entries;

  for (const [, entry] of orderedEntries) {
    const graphs = Array.isArray(entry?.graphs) ? entry.graphs : [];
    const selectedGraph = selectedGraphId
      ? graphs.find((graph) => cleanTerminalBreakoutPlanText(graph?.id || graph?.graphId || graph?.graph_id) === selectedGraphId)
      : graphs[0];
    const identity = terminalArchitectureGraphIdentity(selectedGraph, {
      repoPath: entry?.repoPath || entry?.repo_path || selectedRepoPath,
    });
    if (identity) {
      return identity;
    }
  }

  return terminalArchitectureGraphFromSnapshot(graphState.architectureSnapshot);
}

function terminalArchitectureTimeMs(value) {
  if (typeof value === "number" && Number.isFinite(value) && value > 0) {
    return value;
  }
  const parsed = Date.parse(String(value || ""));
  return Number.isFinite(parsed) ? parsed : 0;
}

function terminalArchitectureItemUpdatedMs(item, pendingItem = null) {
  const queueMeta = normalizeTodoQueueFlatQueueMetadata(item) || {};
  return Math.max(
    terminalArchitectureTimeMs(pendingItem?.updatedAt || pendingItem?.updated_at),
    terminalArchitectureTimeMs(item?.todoStatusUpdatedAt || item?.todo_status_updated_at),
    terminalArchitectureTimeMs(item?.updatedAt || item?.updated_at),
    terminalArchitectureTimeMs(queueMeta.updatedAt || queueMeta.updated_at),
    terminalArchitectureTimeMs(queueMeta.queuedAt || queueMeta.queued_at),
    terminalArchitectureTimeMs(item?.createdAt || item?.created_at),
  );
}

function terminalArchitectureStatusKind(status) {
  const normalized = normalizeTodoQueueLifecycleStatus(status);
  if (["queued"].includes(normalized)) {
    return "queued";
  }
  if (["running"].includes(normalized)) {
    return "running";
  }
  if (["completed"].includes(normalized)) {
    return "done";
  }
  if (["paused", "interrupted"].includes(normalized)) {
    return "awaiting";
  }
  if (["cancelled", "failed", "timed_out"].includes(normalized)) {
    return "failed";
  }
  return "ready";
}

function terminalArchitectureStatusLabel(kind) {
  if (kind === "queued") return "Queued";
  if (kind === "running") return "Running";
  if (kind === "done") return "Done";
  if (kind === "failed") return "Review";
  if (kind === "awaiting") return "Paused";
  return "Ready";
}

function terminalArchitectureRunTitle(run) {
  const target = terminalArchitectureObject(run?.target) || {};
  return cleanTerminalBreakoutPlanText(target.label || target.title || target.name || run?.label || run?.title)
    || cleanTerminalBreakoutPlanText(target.action || run?.action)
    || "Architecture run";
}

function terminalArchitectureRunDetails(run) {
  const target = terminalArchitectureObject(run?.target) || {};
  return terminalBreakoutActivityDetailPairs([
    ["Run", terminalArchitectureRunTitle(run)],
    ["Action", target.action || run?.action],
    ["Environment", run?.environment || run?.env || target.defaultEnv || target.default_env],
    ["Mode", run?.mode || target.defaultMode || target.default_mode],
    ["Scope", target.scope],
    ["Approval", target.requiresApproval || target.requires_approval],
  ]);
}

function terminalArchitectureTodoItemDetails(item) {
  return terminalBreakoutActivityDetailPairs([
    ["Target", getTodoQueueTargetTerminalName(item) || getTodoQueueTargetAgentId(item)],
    ["Terminal", getTodoQueueTargetTerminalId(item) || (
      Number.isInteger(getTodoQueueTargetTerminalIndex(item))
        ? `Terminal ${getTodoQueueTargetTerminalIndex(item) + 1}`
        : ""
    )],
    ["Command", terminalArchitectureRemoteCommand(item).commandId || item?.id],
  ]);
}

function terminalArchitectureDetailPairs(artifact) {
  if (!artifact) {
    return [];
  }
  return terminalBreakoutActivityDetailPairs([
    ["Graph", artifact.graph?.title],
    ["File", artifact.graph?.filePath],
    ["Repo", artifact.graph?.repoPath],
    ["Terminal", artifact.activity?.paneId],
    ["Tool", artifact.activity?.toolName],
    ["Phase", artifact.activity?.phase],
    ...terminalArchitectureRunDetails(artifact.run),
    ...terminalArchitectureTodoItemDetails(artifact.item),
  ]);
}

function terminalArchitectureArtifactSignature(artifact) {
  if (!artifact) {
    return "";
  }
  return [
    artifact.source,
    artifact.statusKind,
    artifact.graph?.id,
    artifact.graph?.filePath,
    artifact.run?.target?.id,
    artifact.run?.environment,
    artifact.run?.mode,
    artifact.item?.id,
    artifact.activity?.paneId,
    artifact.activity?.graphFilePath,
    artifact.activity?.phase,
    artifact.activity?.observedAtMs,
    artifact.updatedAtMs,
  ].map((item) => cleanTerminalBreakoutPlanText(item)).join(":");
}

function terminalArchitectureWorkspaceItems(workspaceTodos, workspaceId) {
  return workspaceTodoItemsForWorkspace(workspaceTodos, workspaceId)
    .filter((item) => terminalArchitectureGraphFromItem(item));
}

function terminalArchitectureActivityStatusKind(activity) {
  const phase = cleanTerminalBreakoutPlanText(activity?.phase);
  if (phase === "graph_changed") return "done";
  if (["graph_editing", "context", "history", "reference"].includes(phase)) return "running";
  return "ready";
}

function terminalArchitectureActivityStatusLabel(activity, kind) {
  const phase = cleanTerminalBreakoutPlanText(activity?.phase);
  if (phase === "graph_changed") return "Updated";
  if (phase === "graph_editing") return "Editing";
  if (phase === "context") return "Context";
  if (phase === "history") return "History";
  if (phase === "reference") return "Reference";
  return terminalArchitectureStatusLabel(kind);
}

function terminalArchitectureArtifactFromActivity(activity, architectureWorkspaceState = null) {
  const source = terminalArchitectureObject(activity);
  if (!source) return null;
  const graph = terminalArchitectureGraphIdentity({
    filePath: source.graphFilePath || source.graph_file_path,
    id: source.graphId || source.graph_id,
    repoPath: source.repoPath || source.repo_path,
    title: source.graphTitle || source.graph_title || "Architecture activity",
  }) || terminalArchitectureSelectedGraphFromState(architectureWorkspaceState);
  if (!graph) return null;
  const statusKind = terminalArchitectureActivityStatusKind(source);
  const headline = source.graphTitle
    || graph.title
    || (source.graphFilePath || "").split(/[\\/]/).filter(Boolean).pop()
    || "Architecture activity";
  return {
    activity: source,
    graph,
    headline,
    item: null,
    run: null,
    source: "terminal-activity",
    statusKind,
    statusLabel: terminalArchitectureActivityStatusLabel(source, statusKind),
    subline: source.graphFilePath || graph.filePath || source.repoPath || graph.repoPath || "Terminal architecture activity",
    updatedAtMs: Number(source.observedAtMs || source.observed_at_ms || 0),
  };
}

function buildTerminalBreakoutArchitectureArtifact({
  architectureTerminalActivity = null,
  architectureWorkspaceState = null,
  pendingItems = {},
  queueItems = [],
  workspaceId = "",
  workspaceTodos = null,
} = {}) {
  const queueCandidates = [
    ...terminalActivityArray(queueItems),
    ...terminalArchitectureWorkspaceItems(workspaceTodos, workspaceId),
  ]
    .map((item) => {
      const graph = terminalArchitectureGraphFromItem(item);
      if (!graph) {
        return null;
      }
      const pendingItem = pendingItems[item?.id] || null;
      const status = getTodoQueueItemCloudStatus(item, pendingItem);
      const statusKind = terminalArchitectureStatusKind(status);
      const run = terminalArchitectureRunFromItem(item);
      const updatedAtMs = terminalArchitectureItemUpdatedMs(item, pendingItem);
      return {
        graph,
        item,
        run,
        source: run ? "run" : "queue",
        statusKind,
        statusLabel: terminalArchitectureStatusLabel(statusKind),
        updatedAtMs,
      };
    })
    .filter(Boolean)
    .sort((left, right) => {
      const rank = { running: 5, queued: 4, awaiting: 3, ready: 2, failed: 1, done: 0 };
      const leftRank = rank[left.statusKind] ?? 0;
      const rightRank = rank[right.statusKind] ?? 0;
      if (leftRank !== rightRank) {
        return rightRank - leftRank;
      }
      return right.updatedAtMs - left.updatedAtMs;
    });

  const activeQueueCandidate = queueCandidates.find((candidate) => (
    !["done", "failed"].includes(candidate.statusKind)
  ));
  const recentInactiveQueueCandidate = queueCandidates.find((candidate) => (
    ["done", "failed"].includes(candidate.statusKind)
      && candidate.updatedAtMs
      && Date.now() - candidate.updatedAtMs < 10 * 60 * 1000
  ));
  const queueArtifact = activeQueueCandidate || recentInactiveQueueCandidate || null;
  if (queueArtifact) {
    const artifact = queueArtifact;
    return {
      ...artifact,
      headline: artifact.run
        ? terminalArchitectureRunTitle(artifact.run)
        : normalizeTodoQueueText(artifact.item?.text).slice(0, 96),
      subline: artifact.graph?.title || artifact.graph?.filePath || "Architecture graph",
    };
  }

  const activityArtifact = terminalArchitectureArtifactFromActivity(
    architectureTerminalActivity,
    architectureWorkspaceState,
  );
  if (activityArtifact) {
    return activityArtifact;
  }

  const selectedGraph = terminalArchitectureSelectedGraphFromState(architectureWorkspaceState);
  if (!selectedGraph) {
    return null;
  }
  return {
    graph: selectedGraph,
    headline: selectedGraph.title,
    item: null,
    run: null,
    source: "selected",
    statusKind: "ready",
    statusLabel: "Ready",
    subline: selectedGraph.filePath || selectedGraph.repoPath || "Selected architecture graph",
    updatedAtMs: 0,
  };
}

function clampTerminalBreakoutArchitectureWindowLayout(layout, containerRect = null) {
  const source = layout && typeof layout === "object" ? layout : {};
  const containerWidth = Math.max(0, Number(containerRect?.width || 0));
  const containerHeight = Math.max(0, Number(containerRect?.height || 0));
  const width = Math.max(
    TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_MIN_WIDTH,
    Number(source.width || TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_DEFAULT_LAYOUT.width),
  );
  const maxX = containerWidth
    ? Math.max(TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_MARGIN, containerWidth - width - TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_MARGIN)
    : Number(source.x || TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_DEFAULT_LAYOUT.x);
  const maxY = containerHeight
    ? Math.max(TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_MARGIN, containerHeight - 120)
    : Number(source.y || TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_DEFAULT_LAYOUT.y);
  return {
    height: Number(source.height || TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_DEFAULT_LAYOUT.height),
    width,
    x: containerWidth
      ? Math.max(TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_MARGIN, Math.min(maxX, Number(source.x || 0)))
      : Number(source.x || TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_DEFAULT_LAYOUT.x),
    y: containerHeight
      ? Math.max(TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_MARGIN, Math.min(maxY, Number(source.y || 0)))
      : Number(source.y || TERMINAL_BREAKOUT_ARCHITECTURE_WINDOW_DEFAULT_LAYOUT.y),
  };
}

function normalizeWorkspaceDocumentPanelEntry(entry) {
  const source = entry && typeof entry === "object" ? entry : {};
  const title = normalizeTodoQueueText(source.title || source.name || source.id || "Document")
    .slice(0, 160) || "Document";
  const typeLabel = normalizeTodoQueueText(source.typeLabel || source.kind || "Document")
    .slice(0, 80) || "Document";
  const key = normalizeTodoQueueText(
    source.key
      || source.documentKey
      || source.document_key
      || source.storageKey
      || source.storage_key
      || source.savedStorageKey
      || source.saved_storage_key
      || source.id
      || source.pathKey
      || source.path_key
      || title,
  ).slice(0, 600);
  return {
    body: normalizeTodoQueueMultilineText(source.body || source.content || "", 50000),
    id: normalizeTodoQueueText(source.id || source.key || title).slice(0, 220),
    kind: normalizeTodoQueueText(source.kind || "document").slice(0, 80),
    key,
    localPath: normalizeTodoQueueText(source.localPath || source.local_path || "").slice(0, 600),
    pathKey: normalizeTodoQueueText(source.pathKey || source.path_key || "").slice(0, 600),
    title,
    typeLabel,
  };
}

function terminalBreakoutPlanEventText(payload, keys) {
  const refs = payload?.refs || {};
  const nestedPayload = payload?.payload || {};
  for (const key of keys) {
    const value = cleanTerminalBreakoutPlanText(refs[key] || payload?.[key] || nestedPayload?.[key]);
    if (value) {
      return value;
    }
  }
  return "";
}

function terminalBreakoutPlanSnapshotFromEventPayload(payload) {
  const snapshot = terminalBreakoutPlanData(
    payload?.planSnapshot
      || payload?.plan_snapshot
      || payload?.snapshot
      || payload?.data?.planSnapshot
      || payload?.data?.plan_snapshot
      || null,
  );
  if (snapshot?.selected_plan || snapshot?.selectedPlan || Array.isArray(snapshot?.history)) {
    return {
      ...snapshot,
      selected_plan: snapshot.selected_plan || snapshot.selectedPlan || null,
      history: Array.isArray(snapshot.history) ? snapshot.history : [],
    };
  }

  const plan = payload?.plan || payload?.selectedPlan || payload?.selected_plan || null;
  if (plan && typeof plan === "object") {
    return {
      history: [plan],
      selected_plan: plan,
      title_max_chars: plan.title_max_chars || plan.titleMaxChars,
    };
  }
  return null;
}

function terminalBreakoutPlanEventMatchesTarget(payload, target) {
  const eventRepoPath = cleanTerminalBreakoutPlanText(payload?.repoPath || payload?.repo_path);
  const targetRepoPath = cleanTerminalBreakoutPlanText(target?.repoPath);
  if (
    eventRepoPath
    && targetRepoPath
    && terminalBreakoutPlanPathIdentity(eventRepoPath) !== terminalBreakoutPlanPathIdentity(targetRepoPath)
  ) {
    return false;
  }

  const eventTaskId = terminalBreakoutPlanEventText(payload, ["taskId", "task_id"]);
  const eventSessionId = terminalBreakoutPlanEventText(payload, ["sessionId", "session_id"]);
  const eventAgentId = terminalBreakoutPlanEventText(payload, ["agentId", "agent_id"]);
  if (target?.taskId && eventTaskId) {
    return eventTaskId === target.taskId;
  }
  if (target?.sessionId && eventSessionId) {
    return eventSessionId === target.sessionId;
  }
  if (target?.agentId && eventAgentId) {
    return eventAgentId === target.agentId;
  }
  return true;
}

function requestTerminalBreakoutPlanSnapshot(target) {
  const cacheKey = target?.cacheKey || terminalBreakoutPlanCacheKey(target);
  const repoPath = cleanTerminalBreakoutPlanText(target?.repoPath);
  if (!cacheKey || !repoPath) {
    return Promise.resolve(null);
  }

  const existingRequest = terminalBreakoutPlanRequests.get(cacheKey);
  if (existingRequest) {
    return existingRequest;
  }

  const command = {
    repoPath,
    input: {
      agentId: cleanTerminalBreakoutPlanText(target?.agentId),
      directRepoTarget: true,
      sessionId: cleanTerminalBreakoutPlanText(target?.sessionId),
      taskId: cleanTerminalBreakoutPlanText(target?.taskId),
    },
  };
  const dbPath = cleanTerminalBreakoutPlanText(target?.dbPath);
  if (dbPath) {
    command.dbPath = dbPath;
  }

  const request = invoke("coordination_terminal_todo_plan_snapshot", command)
    .then(terminalBreakoutPlanData)
    .then((snapshot) => {
      cacheTerminalBreakoutPlanSnapshot(cacheKey, snapshot);
      return snapshot;
    })
    .finally(() => {
      terminalBreakoutPlanRequests.delete(cacheKey);
    });

  terminalBreakoutPlanRequests.set(cacheKey, request);
  return request;
}

function getBreakoutBaseTerminalSize(panelRect, rects = {}) {
  const measuredRects = Object.values(rects || {}).filter((rect) => rect?.width && rect?.height);
  const measuredWidth = measuredRects.length
    ? Math.max(...measuredRects.map((rect) => Number(rect.width || 0)))
    : 0;
  const measuredHeight = measuredRects.length
    ? Math.max(...measuredRects.map((rect) => Number(rect.height || 0)))
    : 0;
  const panelWidth = Number(panelRect?.width || 0);
  const panelHeight = Number(panelRect?.height || 0);

  return {
    height: Math.max(
      TERMINAL_BREAKOUT_MIN_HEIGHT,
      measuredHeight || Math.min(TERMINAL_BREAKOUT_MAX_HEIGHT, panelHeight * 0.62 || 420),
    ),
    width: Math.max(
      TERMINAL_BREAKOUT_MIN_WIDTH,
      measuredWidth || Math.min(TERMINAL_BREAKOUT_MAX_WIDTH, panelWidth * 0.68 || 760),
    ),
  };
}

function getBreakoutTerminalSize(terminalIndex, baseSize, rects = {}) {
  const measuredRect = rects?.[terminalIndex] || {};

  return {
    height: Math.max(TERMINAL_BREAKOUT_MIN_HEIGHT, Number(measuredRect.height || 0) || baseSize.height),
    width: Math.max(TERMINAL_BREAKOUT_MIN_WIDTH, Number(measuredRect.width || 0) || baseSize.width),
  };
}

function getBreakoutPlacementBounds(placements = {}, terminalScale = TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE) {
  const scale = clampBreakoutTerminalScale(terminalScale);
  const normalizedPlacements = Object.values(placements || {})
    .map(normalizeBreakoutPlacement)
    .filter(Boolean);

  if (!normalizedPlacements.length) {
    return null;
  }

  const minX = Math.min(...normalizedPlacements.map((placement) => placement.x));
  const minY = Math.min(...normalizedPlacements.map((placement) => placement.y));
  const maxX = Math.max(...normalizedPlacements.map((placement) => placement.x + (placement.width * scale)));
  const maxY = Math.max(...normalizedPlacements.map((placement) => placement.y + (placement.height * scale)));

  return {
    centerX: minX + ((maxX - minX) / 2),
    centerY: minY + ((maxY - minY) / 2),
    height: maxY - minY,
    maxX,
    maxY,
    minX,
    minY,
    width: maxX - minX,
  };
}

function buildSpreadBreakoutPlacements({
  existingPlacements = {},
  panelRect,
  preserveExisting = true,
  rects = {},
  terminalScale = TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE,
  terminalIndexes = [],
} = {}) {
  const scale = clampBreakoutTerminalScale(terminalScale);
  const baseSize = getBreakoutBaseTerminalSize(panelRect, rects);
  const terminalSizes = (terminalIndexes || []).map((terminalIndex) => ({
    terminalIndex,
    ...getBreakoutTerminalSize(terminalIndex, baseSize, rects),
  }));
  const normalizedExistingPlacements = normalizeBreakoutPlacements(existingPlacements, terminalIndexes);
  const existingPlacementCount = Object.keys(normalizedExistingPlacements).length;
  const shouldPreserveExisting = preserveExisting && existingPlacementCount > 0;

  if (shouldPreserveExisting) {
    const placements = { ...normalizedExistingPlacements };
    const missingSizes = terminalSizes.filter(({ terminalIndex }) => !placements[terminalIndex]);
    const bounds = getBreakoutPlacementBounds(placements, scale);
    let maxZ = Math.max(0, ...Object.values(placements)
      .map((placement) => Number.parseInt(placement?.z, 10) || 0));
    let cursorX = bounds ? bounds.maxX + TERMINAL_BREAKOUT_MIN_GAP_X : 0;
    const cursorY = bounds ? bounds.minY : 0;

    missingSizes.forEach(({ height, terminalIndex, width }) => {
      placements[terminalIndex] = {
        height,
        width,
        x: cursorX,
        y: cursorY,
        z: maxZ + 1,
      };
      maxZ += 1;
      cursorX += (width * scale) + TERMINAL_BREAKOUT_MIN_GAP_X;
    });

    return {
      maxZ,
      placements,
    };
  }

  const maxTerminalWidth = terminalSizes.length
    ? Math.max(...terminalSizes.map((size) => size.width))
    : baseSize.width;
  const maxTerminalHeight = terminalSizes.length
    ? Math.max(...terminalSizes.map((size) => size.height))
    : baseSize.height;
  const maxVisibleWidth = maxTerminalWidth * scale;
  const maxVisibleHeight = maxTerminalHeight * scale;
  const columns = Math.max(1, Math.min(4, Math.ceil(Math.sqrt(Math.max(1, terminalIndexes.length)))));
  const cellWidth = maxVisibleWidth + TERMINAL_BREAKOUT_MIN_GAP_X;
  const cellHeight = maxVisibleHeight + TERMINAL_BREAKOUT_MIN_GAP_Y;
  const nextPlacements = {};
  let maxZ = 0;

  terminalSizes.forEach(({ height, terminalIndex, width }, orderIndex) => {
    const columnIndex = orderIndex % columns;
    const rowIndex = Math.floor(orderIndex / columns);
    const visibleWidth = width * scale;
    const visibleHeight = height * scale;
    nextPlacements[terminalIndex] = {
      height,
      width,
      x: (columnIndex * cellWidth) + ((maxVisibleWidth - visibleWidth) / 2),
      y: (rowIndex * cellHeight) + ((maxVisibleHeight - visibleHeight) / 2),
      z: orderIndex + 1,
    };
    maxZ = Math.max(maxZ, orderIndex + 1);
  });

  return {
    maxZ,
    placements: nextPlacements,
  };
}

function getTerminalBreakoutMaxZ(...placementGroups) {
  return placementGroups
    .flatMap((group) => Object.values(group || {}))
    .map((placement) => Number.parseInt(placement?.z, 10) || 0)
    .reduce((maxValue, z) => Math.max(maxValue, z), 0);
}

function buildTerminalBreakoutDocumentPlacement({
  existingPlacement = null,
  terminalPlacements = {},
  terminalScale = TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE,
} = {}) {
  const normalizedExisting = normalizeBreakoutPlacement(existingPlacement);
  if (normalizedExisting) {
    return normalizedExisting;
  }

  const scale = clampBreakoutTerminalScale(terminalScale);
  const width = TERMINAL_BREAKOUT_DOCUMENT_WINDOW_DEFAULT_LAYOUT.width;
  const height = TERMINAL_BREAKOUT_DOCUMENT_WINDOW_DEFAULT_LAYOUT.height;
  const terminalBounds = getBreakoutPlacementBounds(terminalPlacements, scale);
  const x = terminalBounds
    ? terminalBounds.minX - ((width * scale) + TERMINAL_BREAKOUT_MIN_GAP_X)
    : TERMINAL_BREAKOUT_DOCUMENT_WINDOW_DEFAULT_LAYOUT.x;
  const y = terminalBounds
    ? terminalBounds.minY
    : TERMINAL_BREAKOUT_DOCUMENT_WINDOW_DEFAULT_LAYOUT.y;
  return {
    height,
    width,
    x,
    y,
    z: getTerminalBreakoutMaxZ(terminalPlacements) + 1,
  };
}

function breakoutPlacementsWithDocumentPanel(placements, documentPlacement = null, enabled = false) {
  const normalizedDocumentPlacement = enabled
    ? normalizeBreakoutPlacement(documentPlacement)
    : null;
  return normalizedDocumentPlacement
    ? { ...(placements || {}), document: normalizedDocumentPlacement }
    : placements;
}

function getBreakoutScreenRect(
  placement,
  viewport,
  terminalScale = TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE,
) {
  const normalizedPlacement = normalizeBreakoutPlacement(placement);
  const normalizedViewport = normalizeBreakoutViewport(viewport);
  const scale = clampBreakoutTerminalScale(terminalScale);

  if (!normalizedPlacement) {
    return null;
  }

  return {
    height: normalizedPlacement.height * normalizedViewport.zoom * scale,
    left: (normalizedPlacement.x * normalizedViewport.zoom) + normalizedViewport.x,
    top: (normalizedPlacement.y * normalizedViewport.zoom) + normalizedViewport.y,
    width: normalizedPlacement.width * normalizedViewport.zoom * scale,
  };
}

function getBreakoutFitViewport(
  panelRect,
  placements = {},
  preferredZoom = null,
  terminalScale = TERMINAL_BREAKOUT_DEFAULT_TERMINAL_SCALE,
) {
  const panelWidth = Number(panelRect?.width || 0);
  const panelHeight = Number(panelRect?.height || 0);
  const bounds = getBreakoutPlacementBounds(placements, terminalScale);

  if (!panelWidth || !panelHeight || !bounds) {
    return TERMINAL_BREAKOUT_DEFAULT_VIEWPORT;
  }

  const availableWidth = Math.max(1, panelWidth - (TERMINAL_BREAKOUT_FIT_MARGIN * 2));
  const availableHeight = Math.max(1, panelHeight - (TERMINAL_BREAKOUT_FIT_MARGIN * 2));
  const fitZoom = clampBreakoutZoom(Math.min(
    availableWidth / Math.max(1, bounds.width),
    availableHeight / Math.max(1, bounds.height),
  ));
  const zoom = Number.isFinite(Number(preferredZoom))
    ? clampBreakoutZoom(Math.min(Number(preferredZoom), fitZoom))
    : fitZoom;

  return {
    x: Math.round((panelWidth / 2) - (bounds.centerX * zoom)),
    y: Math.round((panelHeight / 2) - (bounds.centerY * zoom)),
    zoom,
  };
}

function getOrchestratorVoiceHistoryWorkspaceId(workspaceId) {
  return String(workspaceId || "default").trim() || "default";
}

function normalizeTodoQueueText(value) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .trim()
    .slice(0, TODO_QUEUE_MAX_TEXT_LENGTH);
}

function normalizeTodoQueueMultilineText(value, maxLength = TODO_QUEUE_MAX_NOTE_TEXT_LENGTH) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .trim()
    .slice(0, maxLength);
}

const TODO_QUEUE_CANONICAL_LIFECYCLE_STATUSES = new Set([
  "listed",
  "queued",
  "running",
  "paused",
  "completed",
  "cancelled",
  "interrupted",
  "timed_out",
  "failed",
  "deleted",
]);

function normalizeTodoQueueLifecycleStatus(value) {
  const status = String(value || "").trim().toLowerCase();
  return TODO_QUEUE_CANONICAL_LIFECYCLE_STATUSES.has(status) ? status : "";
}

function todoQueueLifecycleStatusIsSettled(status) {
  return ["completed", "cancelled", "deleted", "failed", "interrupted", "timed_out"]
    .includes(normalizeTodoQueueLifecycleStatus(status));
}

function getTodoQueueLifecycleStatusUpdatedAt(item) {
  return String(
    item?.todoStatusUpdatedAt
      || item?.todo_status_updated_at
      || item?.statusUpdatedAt
      || item?.status_updated_at
      || "",
  ).trim();
}

function getTodoQueueCanonicalLifecycle(item, fallback = "") {
  return {
    evidence: null,
    status: normalizeTodoQueueLifecycleStatus(
      item?.todoStatus
        || item?.todo_status
        || item?.cloudStatus
        || item?.cloud_status
        || item?.status
        || fallback,
    ),
    statusUpdatedAt: getTodoQueueLifecycleStatusUpdatedAt(item),
  };
}

function getTodoQueueCanonicalLifecycleStatus(item, fallback = "") {
  return getTodoQueueCanonicalLifecycle(item, fallback).status;
}

function normalizeTodoQueueDispatchAction(value) {
  const action = String(value || "").trim().toLowerCase().replace(/[-\s]+/g, "_");
  if (["resume", "manual_resume", "resume_unfinished", "resume_unfinished_plan_tasks"].includes(action)) {
    return "resume";
  }
  if (["retry", "requeue", "manual_requeue", "rerun", "restart"].includes(action)) {
    return "retry";
  }
  if (["dispatch", "send", "queue", "start"].includes(action)) {
    return "dispatch";
  }
  return action;
}

function normalizeTodoQueueDeviceSendMode(value, fallback = "listed") {
  const mode = String(value || "").trim().toLowerCase().replace(/[-\s.]+/g, "_");
  if (!mode) {
    return fallback === "queued" ? "queued" : "listed";
  }
  if (["queue", "queued", "dispatch", "active_queue", "run_if_online"].includes(mode)) {
    return "queued";
  }
  return "listed";
}

function encodeTodoQueueDeviceSendValue(mode, targetId) {
  return JSON.stringify({
    mode: normalizeTodoQueueDeviceSendMode(mode),
    targetId: String(targetId || "").trim(),
  });
}

function parseTodoQueueDeviceSendValue(value) {
  const raw = String(value || "").trim();
  if (!raw) {
    return { mode: "listed", targetId: "" };
  }
  try {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === "object") {
      return {
        mode: normalizeTodoQueueDeviceSendMode(parsed.mode),
        targetId: String(parsed.targetId || parsed.target_id || "").trim(),
      };
    }
  } catch (_) {
    // Older select values were bare target ids and meant queued dispatch.
  }
  return { mode: "queued", targetId: raw };
}

function todoQueueDispatchActionIsResume(value) {
  return normalizeTodoQueueDispatchAction(value) === "resume";
}

function getTodoQueueItemTodoId(item) {
  return String(
    item?.todoId
      || item?.todo_id
      || item?.clientTodoId
      || item?.client_todo_id
      || item?.remoteCommand?.todoId
      || item?.remoteCommand?.todo_id
      || item?.planTask?.clientTodoId
      || item?.planTask?.client_todo_id
      || item?.planTask?.todoId
      || item?.planTask?.todo_id
      || item?.id
      || "",
  ).trim();
}

function getTodoQueueDispatchAction(item, source = "", fields = {}) {
  const queueMeta = getTodoQueueRawQueueMetadata(item) || {};
  const explicitAction = normalizeTodoQueueDispatchAction(
    fields.todoAction
      || fields.todo_action
      || fields.action
      || item?.todoAction
      || item?.todo_action
      || item?.queueAction
      || item?.queue_action
      || queueMeta.todoAction
      || queueMeta.todo_action
      || queueMeta.action
      || item?.remoteCommand?.todoAction
      || item?.remoteCommand?.todo_action
      || item?.remoteCommand?.action
      || "",
  );
  if (explicitAction) {
    return explicitAction;
  }
  const reasonText = [
    source,
    fields.reason,
    queueMeta.reason,
    item?.reason,
  ].join(" ").toLowerCase();
  if (reasonText.includes("resume") && !reasonText.includes("retry") && !reasonText.includes("requeue")) {
    return "resume";
  }
  const status = getTodoQueueCanonicalLifecycleStatus(item);
  if (status === "paused") {
    return "resume";
  }
  if (["cancelled", "interrupted", "timed_out", "failed"].includes(status)) {
    return "retry";
  }
  return "dispatch";
}

function getTodoQueueItemCloudStatus(item, pendingItem = null) {
  const explicitStatus = getTodoQueueCanonicalLifecycleStatus(item);
  if (todoQueueLifecycleStatusIsSettled(explicitStatus)) {
    return explicitStatus;
  }
  if (pendingItem) {
    return getTodoQueuePendingPhase(pendingItem) === "queued" ? "queued" : "running";
  }
  if (explicitStatus) {
    return explicitStatus;
  }
  const queueMeta = normalizeTodoQueueFlatQueueMetadata(item);
  if (queueMeta) {
    return queueMeta.phase === "queued" ? "queued" : "running";
  }
  return "listed";
}

function getTodoQueueItemWithCloudStatus(item, status, fields = {}) {
  if (!item || typeof item !== "object") {
    return item;
  }
  const nextStatus = normalizeTodoQueueLifecycleStatus(status) || "listed";
  const updatedAt = String(fields.updatedAt || new Date().toISOString());
  const completedAt = String(fields.completedAt || updatedAt);
  const cancelledAt = String(fields.cancelledAt || fields.canceledAt || updatedAt);
  const pausedAt = String(fields.pausedAt || fields.parkedAt || updatedAt);
  const interruptedAt = String(fields.interruptedAt || updatedAt);
  const timedOutAt = String(fields.timedOutAt || fields.timeoutAt || updatedAt);
  const failedAt = String(fields.failedAt || updatedAt);
  const deletedAt = String(fields.deletedAt || updatedAt);
  return {
    ...item,
    status: nextStatus,
    todoStatus: nextStatus,
    updatedAt,
    todoStatusUpdatedAt: updatedAt,
    ...(nextStatus === "completed" ? { completedAt, todoCompletedAt: completedAt } : {}),
    ...(nextStatus === "cancelled" ? { cancelledAt, todoCancelledAt: cancelledAt } : {}),
    ...(nextStatus === "paused" ? { pausedAt, todoPausedAt: pausedAt } : {}),
    ...(nextStatus === "interrupted" ? { interruptedAt, todoInterruptedAt: interruptedAt } : {}),
    ...(nextStatus === "timed_out" ? { timedOutAt, todoTimedOutAt: timedOutAt } : {}),
    ...(nextStatus === "failed" ? { failedAt, todoFailedAt: failedAt } : {}),
    ...(nextStatus === "deleted" ? { deletedAt, todoDeletedAt: deletedAt } : {}),
    ...(fields.reason ? { statusReason: String(fields.reason), todoStatusReason: String(fields.reason) } : {}),
  };
}

function getTodoQueueItemWithTerminalAssignment(item, fields = {}) {
  if (!item || typeof item !== "object") {
    return item;
  }
  const targetAgentId = normalizeTodoTerminalAgentId(fields.targetAgentId || fields.targetRole || "");
  const targetTerminalId = normalizeTodoTerminalIdentity(
    fields.targetTerminalId || fields.terminalId || fields.paneId || "",
  );
  const targetTerminalIndex = normalizeTodoTerminalIndex(
    fields.targetTerminalIndex ?? fields.terminalIndex,
  );
  const targetTerminalName = normalizeTodoTerminalName(
    fields.targetTerminalName
      || fields.target_terminal_name
      || fields.terminalName
      || fields.terminal_name
      || fields.targetName
      || fields.target_name
      || "",
  );
  const targetThreadId = normalizeTodoTerminalIdentity(fields.targetThreadId || fields.threadId || "");
  const targetColorSlot = normalizeTerminalColorSlot(
    fields.targetColorSlot ?? fields.colorSlot,
  );
  const targetTerminalColor = normalizeTerminalHexColor(
    fields.targetTerminalColor || fields.terminalColor || "",
  );
  return {
    ...item,
    ...(targetAgentId ? { targetAgentId } : {}),
    ...(targetTerminalId ? { targetTerminalId } : {}),
    ...(Number.isInteger(targetTerminalIndex) ? { targetTerminalIndex } : {}),
    ...(targetTerminalName ? { targetTerminalName } : {}),
    ...(targetThreadId ? { targetThreadId } : {}),
    ...(Number.isInteger(targetColorSlot) ? { targetColorSlot } : {}),
    ...(targetTerminalColor ? { targetTerminalColor } : {}),
  };
}

function getTodoQueueRecoverableStatus(item) {
  const status = getTodoQueueItemCloudStatus(item);
  return ["cancelled", "paused", "interrupted", "timed_out", "failed"].includes(status) ? status : "";
}

function todoQueueRecoverableStatusLabel(status) {
  if (status === "timed_out") return "timed out";
  if (status === "cancelled") return "cancelled";
  if (status === "paused") return "paused";
  if (status === "interrupted") return "interrupted";
  if (status === "failed") return "failed";
  return "";
}

function getTodoQueueLineCount(value) {
  const text = normalizeTodoQueueMultilineText(value);
  return text ? text.split("\n").length : 0;
}

function resizeTodoQueueTextAreaToContent(element) {
  if (!element) {
    return;
  }

  element.style.height = "auto";
  element.style.height = `${Math.ceil(element.scrollHeight || 0)}px`;
}

function getTodoQueuePastedLinesLabel(lineCount) {
  return `[pasted-lines ${Math.max(1, Number(lineCount || 0))}]`;
}

function getTodoQueueNoteTitle(value) {
  const normalizedTitle = String(value || "")
    .replace(/\s+/g, " ")
    .trim();

  if (!normalizedTitle) {
    return "Pasted note";
  }

  return normalizedTitle.length > TODO_QUEUE_NOTE_TITLE_LENGTH
    ? `${normalizedTitle.slice(0, TODO_QUEUE_NOTE_TITLE_LENGTH - 3)}...`
    : normalizedTitle;
}

function normalizeTodoQueueNote(value) {
  const note = typeof value === "string"
    ? { text: value }
    : value && typeof value === "object"
      ? value
      : null;
  const text = normalizeTodoQueueMultilineText(note?.text || note?.content);

  if (!text) {
    return null;
  }

  const lineCount = getTodoQueueLineCount(text);

  return {
    lineCount,
    text,
    title: getTodoQueuePastedLinesLabel(lineCount),
    preview: getTodoQueueNoteTitle(note?.preview || note?.title || text),
  };
}

function normalizeTodoQueueKind(value) {
  return "todo";
}

function normalizeTodoQueueSource(value) {
  return String(value || "").trim().slice(0, 80);
}

function normalizeRemoteCommandKind(value) {
  return String(value || "")
    .trim()
    .replace(/([a-z0-9])([A-Z])/g, "$1_$2")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

function getTodoQueueRemoteCommandObject(item) {
  if (item?.remoteCommand && typeof item.remoteCommand === "object") {
    return item.remoteCommand;
  }
  if (item?.remote_command && typeof item.remote_command === "object") {
    return item.remote_command;
  }
  return {};
}

function isTerminalOrchestratorRemoteCommand(item) {
  const remoteCommand = getTodoQueueRemoteCommandObject(item);
  const commandKind = normalizeRemoteCommandKind(
    remoteCommand.commandKind
      || remoteCommand.command_kind
      || remoteCommand.kind
      || remoteCommand.type
      || item?.commandKind
      || item?.command_kind
      || item?.command_kind_id
      || "",
  );
  return commandKind === "terminal_orchestrator_send_message";
}

function normalizeTerminalCoordinationTarget(value) {
  const target = value && typeof value === "object" && !Array.isArray(value) ? value : null;
  if (!target) {
    return null;
  }
  const repoPath = String(target.repoPath || target.repo_path || "").trim();
  if (!repoPath) {
    return null;
  }
  return {
    repoPath,
    dbPath: String(target.dbPath || target.db_path || "").trim(),
    mountId: String(target.mountId || target.mount_id || "").trim(),
    projectName: String(target.projectName || target.project_name || "").trim(),
    projectKind: String(target.projectKind || target.project_kind || "").trim(),
    workspaceRelativePath: String(
      target.workspaceRelativePath || target.workspace_relative_path || "",
    ).trim(),
    isWorkspaceRoot: Boolean(target.isWorkspaceRoot || target.is_workspace_root),
  };
}

function normalizeTerminalCoordinationTargets(value) {
  return (Array.isArray(value) ? value : [])
    .map(normalizeTerminalCoordinationTarget)
    .filter(Boolean);
}

function terminalCoordinationTargetForIndex(targets, _terminalIndex, fallbackRoot = "") {
  const normalizedTargets = normalizeTerminalCoordinationTargets(targets);
  if (!normalizedTargets.length) {
    return fallbackRoot
      ? { repoPath: fallbackRoot, mountId: "", projectName: "", projectKind: "workspace_root", workspaceRelativePath: "", isWorkspaceRoot: true }
      : null;
  }

  return normalizedTargets[0];
}

function normalizeVoiceAgentQueueArguments(value) {
  if (typeof value === "string") {
    try {
      const parsed = JSON.parse(value);
      return parsed && typeof parsed === "object" ? parsed : {};
    } catch {
      return {};
    }
  }

  return value && typeof value === "object" ? value : {};
}

function normalizeVoiceAgentManagementAgent(value) {
  const agentType = String(value || "").trim();
  if (["any", "codex", "claude", "opencode"].includes(agentType)) return agentType;
  return "";
}

function normalizeVoiceAgentOpenCodingAgentsAction(value) {
  const action = String(value || "").trim();
  if (action === "ensure_count" || action === "spawn_count") return action;
  return "";
}

function getVoiceAgentOpenCodingAgentsRequestSummary(args = {}) {
  const action = normalizeVoiceAgentOpenCodingAgentsAction(args.action);
  const agentId = normalizeVoiceAgentManagementAgent(args.agent_type);
  const count = Math.max(1, Math.min(12, Number.parseInt(args.count, 10) || 1));
  const agentLabel = agentId && agentId !== "any" ? agentId : "agent";

  if (action === "ensure_count") {
    return `Open ${count} total ${agentLabel} terminal${count === 1 ? "" : "s"}.`;
  }
  return `Open ${count} more ${agentLabel} terminal${count === 1 ? "" : "s"}.`;
}

function getVoiceAgentHighlightStringValues(...values) {
  const result = [];
  const append = (value) => {
    if (Array.isArray(value)) {
      value.forEach(append);
      return;
    }
    if (value == null) {
      return;
    }
    if (typeof value === "object") {
      append(
        value.id
          || value.terminal_id
          || value.terminalId
          || value.target_terminal_id
          || value.targetTerminalId
          || value.pane_id
          || value.paneId
          || value.terminal_name
          || value.terminalName
          || value.terminal_nickname
          || value.terminalNickname
          || value.target_terminal_name
          || value.targetTerminalName
          || value.display_name
          || value.displayName
          || value.name
          || value.label
          || value.title
          || "",
      );
      return;
    }
    String(value)
      .split(",")
      .map((entry) => entry.trim())
      .filter(Boolean)
      .forEach((entry) => result.push(entry));
  };
  values.forEach(append);
  return Array.from(new Set(result));
}

function getVoiceAgentHighlightTerminalNameValues(...sources) {
  return getVoiceAgentHighlightStringValues(
    ...sources.flatMap((source) => {
      if (!source || typeof source !== "object") {
        return [source];
      }
      return [
        source.terminalName,
        source.terminal_name,
        source.terminalNickname,
        source.terminal_nickname,
        source.targetTerminalName,
        source.target_terminal_name,
        source.displayName,
        source.display_name,
        source.name,
        source.label,
        source.title,
        source.agentDisplayName,
        source.agent_display_name,
      ];
    }),
  ).map((value) => normalizeTodoTerminalName(value));
}

function getVoiceAgentHighlightIntegerValues(...values) {
  return getVoiceAgentHighlightStringValues(...values)
    .map((value) => Number.parseInt(value, 10))
    .filter((value) => Number.isInteger(value) && value >= 0);
}

function getVoiceAgentWorkspaceTerminalCanonicalIds(workspaceId, terminalIndex, agentType) {
  const safeWorkspaceId = String(workspaceId || "").trim();
  const normalizedIndex = Number.parseInt(terminalIndex, 10);
  if (!safeWorkspaceId || !Number.isInteger(normalizedIndex) || normalizedIndex < 0) {
    return [];
  }
  const baseId = `workspace-terminal-${safeWorkspaceId}-${normalizedIndex}`;
  const normalizedAgentType = normalizeTodoTerminalAgentId(agentType || "");
  return normalizedAgentType ? [baseId, `${baseId}-${normalizedAgentType}`] : [baseId];
}

function getVoiceAgentHighlightQuery(args = {}) {
  return normalizeTodoQueueText(
    args.query
      || args.topic
      || args.todo_query
      || args.todoQuery
      || args.session_query
      || args.sessionQuery
      || args.todo_text
      || args.todoText
      || args.text
      || "",
  );
}

function getVoiceAgentHighlightSessionSummaryItems(summary) {
  const items = summary?.summaryItems
    || summary?.summary_items
    || summary?.rawTodos
    || summary?.raw_todos
    || summary?.rawRecentTodos
    || summary?.raw_recent_todos
    || [];
  const chunks = summary?.chunks || [];
  return [
    ...(Array.isArray(items) ? items : []),
    ...(Array.isArray(chunks) ? chunks : []),
  ];
}

function voiceAgentHighlightSessionSummaryMatchesQuery(summary, query) {
  if (!summary || typeof summary !== "object" || !query) {
    return false;
  }
  const values = [
    summary.title,
    summary.summary,
    summary.summaryText,
    summary.summary_text,
    summary.fallbackSummary,
    summary.fallback_summary,
  ];
  getVoiceAgentHighlightSessionSummaryItems(summary).forEach((item) => {
    values.push(
      item?.text,
      item?.summary,
      item?.summaryText,
      item?.summary_text,
      item?.fallbackSummary,
      item?.fallback_summary,
      item?.todo?.text,
      item?.todo?.title,
    );
    const inputTodos = item?.compressionJob?.inputTodos
      || item?.compression_job?.input_todos
      || item?.inputTodos
      || item?.input_todos
      || [];
    if (Array.isArray(inputTodos)) {
      inputTodos.forEach((todo) => {
        values.push(todo?.text, todo?.title, todo?.todoText, todo?.todo_text);
      });
    }
  });
  return values.some((value) => (
    normalizeTodoQueueText(value || "").toLowerCase().includes(query)
  ));
}

function getVoiceAgentHighlightSessionSummaryRefs(summary) {
  const session = summary?.session || summary?.sessionRef || summary?.session_ref || {};
  return {
    sessionIds: getVoiceAgentHighlightStringValues(
	      summary?.providerSessionId,
	      summary?.provider_session_id,
	      summary?.nativeSessionId,
	      summary?.native_session_id,
	      summary?.forkFromProviderSessionId,
	      summary?.fork_from_provider_session_id,
	      summary?.forkedFromProviderSessionId,
	      summary?.forked_from_provider_session_id,
	      summary?.sharedHistoryId,
	      summary?.shared_history_id,
	      summary?.historyGroupId,
	      summary?.history_group_id,
	      summary?.relatedProviderSessionIds,
	      summary?.related_provider_session_ids,
	      summary?.sessionId,
	      summary?.session_id,
	      session?.providerSessionId,
	      session?.provider_session_id,
	      session?.nativeSessionId,
	      session?.native_session_id,
	      session?.forkFromProviderSessionId,
	      session?.fork_from_provider_session_id,
	      session?.forkedFromProviderSessionId,
	      session?.forked_from_provider_session_id,
	      session?.sharedHistoryId,
	      session?.shared_history_id,
	      session?.historyGroupId,
	      session?.history_group_id,
	      session?.relatedProviderSessionIds,
	      session?.related_provider_session_ids,
	      session?.sessionId,
	      session?.session_id,
    ),
    terminalIds: getVoiceAgentHighlightStringValues(
      summary?.terminalId,
      summary?.terminal_id,
      summary?.targetTerminalId,
      summary?.target_terminal_id,
      session?.terminalId,
      session?.terminal_id,
      session?.targetTerminalId,
      session?.target_terminal_id,
    ),
    terminalNames: getVoiceAgentHighlightTerminalNameValues(summary, session),
    terminalIndex: normalizeTodoTerminalIndex(
      summary?.terminalIndex
        ?? summary?.terminal_index
        ?? session?.terminalIndex
        ?? session?.terminal_index,
    ),
  };
}

function voiceAgentHighlightScopeIsAll(args = {}) {
  const scope = String(
    args.scope
      || args.target_scope
      || args.targetScope
      || args.selection
      || args.target
      || "",
  ).trim().toLowerCase().replace(/[\s-]+/g, "_");
  return Boolean(args.all)
    || scope === "all"
    || scope === "every"
    || scope === "all_terminals"
    || scope === "matching_terminals";
}

function voiceAgentHighlightScopeIsCurrent(args = {}) {
  const scope = String(
    args.scope
      || args.target_scope
      || args.targetScope
      || args.selection
      || args.target
      || "",
  ).trim().toLowerCase().replace(/[\s-]+/g, "_");
  return Boolean(args.current)
    || Boolean(args.active)
    || scope === "current"
    || scope === "active"
    || scope === "this_terminal";
}

function getVoiceAgentHighlightTerminalRequestSummary(args = {}) {
  const agentType = normalizeVoiceAgentManagementAgent(
    args.agent_type
      || args.agentType
      || args.agent_kind
      || args.agentKind
      || args.target_agent_id
      || args.targetAgentId,
  );
  const agentLabel = agentType && agentType !== "any" ? `${agentType} ` : "";
  const query = normalizeVoiceHistoryText(getVoiceAgentHighlightQuery(args), 120);
  const terminalIds = getVoiceAgentHighlightStringValues(
    args.terminal_id,
    args.terminalId,
    args.terminal_ids,
    args.terminalIds,
    args.target_terminal_id,
    args.targetTerminalId,
    args.pane_id,
    args.paneId,
  );
  const terminalIndexes = getVoiceAgentHighlightIntegerValues(
    args.terminal_index,
    args.terminalIndex,
    args.terminal_indexes,
    args.terminalIndexes,
    args.target_terminal_index,
    args.targetTerminalIndex,
  );
  const explicitCount = terminalIds.length + terminalIndexes.length;

  if (voiceAgentHighlightScopeIsAll(args)) {
    return `Highlight all ${agentLabel}terminals.`;
  }
  if (query) {
    return `Highlight ${agentLabel}terminal(s) matching "${query}".`;
  }
  if (explicitCount > 0) {
    return `Highlight ${explicitCount} ${agentLabel}terminal${explicitCount === 1 ? "" : "s"}.`;
  }
  if (voiceAgentHighlightScopeIsCurrent(args)) {
    return "Highlight the current terminal.";
  }
  return `Highlight ${agentLabel}terminal(s).`;
}

function getVoiceAgentToolCallSignature(toolCall) {
  const callId = String(toolCall?.call_id || toolCall?.callId || "").trim();
  const toolName = String(toolCall?.name || toolCall?.tool_name || toolCall?.toolName || "").trim();
  const fallbackSignature = JSON.stringify(toolCall?.arguments || toolCall?.args || {});
  return callId || `${toolName}:${fallbackSignature}`;
}

function getVoiceAgentEventKind(event) {
  return cloudVoiceAgentEventKind(event);
}

function getVoiceAgentEventMarker(event) {
  return String(
    event?.response_kind
      || event?.responseKind
      || event?.phase
      || event?.status
      || event?.scope
      || "",
  ).trim().toLowerCase();
}

function isVoiceAgentTtsEventKind(kind) {
  return kind === "voice_agent_tts_start"
    || kind === "voice_agent_tts_audio"
    || kind === "voice_agent_tts_end";
}

function isVoiceAgentFastResponseEvent(event) {
  const kind = getVoiceAgentEventKind(event);
  const marker = getVoiceAgentEventMarker(event);
  return Boolean(
    event?.fast_response
      || event?.fastResponse
      || event?.is_fast_response
      || event?.isFastResponse
      || event?.fast_llm_response
      || event?.fastLlmResponse,
  )
    || kind === "voice_agent_fast_llm_feedback"
    || kind === "voice_agent_initial_llm_feedback"
    || marker === "fast_response"
    || marker === "fast_llm_response"
    || marker === "initial_fast_response";
}

function normalizeFastVoiceAgentFeedbackEvent(event) {
  return {
    ...(event || {}),
    final: false,
    kind: "voice_agent_llm_feedback",
    status: String(event?.status || "fast_response").trim() || "fast_response",
  };
}

function cleanPublicVoiceAgentText(value) {
  let text = String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .trim();

  for (let index = 0; index < 3; index += 1) {
    const nextText = text
      .replace(/^(?:in\s+)?(?:(?:repo_id|workspace_id)=[^\s,]+(?:\s+(?:repo_id|workspace_id)=[^\s,]+)*),?\s*/i, "")
      .trim();
    if (!nextText || nextText === text) {
      break;
    }
    text = nextText;
  }

  return text;
}

function getVoiceAgentQueueTodoEntries(args) {
  const entries = ["todos", "items", "tasks"].find((key) => Array.isArray(args?.[key]));
  if (entries) {
    return args[entries].filter((item) => item && typeof item === "object").slice(0, 12);
  }
  return args && typeof args === "object" ? [args] : [];
}

function getVoiceAgentQueueTargetFields(args = {}) {
  const rawAgentId = normalizeVoiceAgentManagementAgent(
    args.target_agent_id
      || args.targetAgentId
      || args.agent_type
      || args.agentType
      || args.target_role
      || args.targetRole,
  );
  const targetAgentId = rawAgentId && rawAgentId !== "any" ? rawAgentId : "";
  const targetTerminalIndex = normalizeTodoTerminalIndex(
    args.target_terminal_index
      ?? args.targetTerminalIndex
      ?? args.terminal_index
      ?? args.terminalIndex
      ?? args.lane
      ?? args.lane_index
      ?? args.laneIndex,
  );
  const targetTerminalId = normalizeTodoTerminalIdentity(
    args.target_terminal_id
      || args.targetTerminalId
      || args.terminal_id
      || args.terminalId
      || args.pane_id
      || args.paneId
      || "",
  );
  const providerSessionId = normalizeTodoTerminalIdentity(
    args.provider_session_id
      || args.providerSessionId
      || args.native_session_id
      || args.nativeSessionId
      || args.session_id
      || args.sessionId
      || args.target_session_id
      || args.targetSessionId
      || args.target_thread_id
      || args.targetThreadId
      || args.thread_id
      || args.threadId
      || "",
  );
  const targetTerminalName = normalizeTodoTerminalName(
    args.target_terminal_name
      || args.targetTerminalName
      || args.terminal_name
      || args.terminalName
      || args.target_name
      || args.targetName
      || args.name
      || "",
  );
  const targetColorSlot = normalizeTerminalColorSlot(
    args.target_color_slot
      ?? args.targetColorSlot
      ?? args.color_slot
      ?? args.colorSlot,
  );
  const targetTerminalColor = normalizeTerminalHexColor(
    args.target_terminal_color
      || args.targetTerminalColor
      || args.terminal_color
      || args.terminalColor
      || args.color
      || "",
  );
  const targetExplicit = Boolean(
    targetTerminalId
      || Number.isInteger(targetTerminalIndex)
      || targetTerminalName
      || providerSessionId
      || Number.isInteger(targetColorSlot)
      || targetTerminalColor,
  );
  return {
    providerSessionId,
    targetAgentId,
    targetColorSlot,
    targetExplicit,
    targetTerminalColor,
    targetTerminalId,
    targetTerminalIndex,
    targetTerminalName,
  };
}

function createTodoQueueItemsFromVoiceAgentToolCall(toolCall, options = {}) {
  const args = normalizeVoiceAgentQueueArguments(toolCall?.arguments || toolCall?.args);
  return getVoiceAgentQueueTodoEntries(args)
    .map((entry) => createTodoQueueItemFromVoiceAgentTodoEntry(entry, toolCall, args, options))
    .filter(Boolean);
}

function createTodoQueueItemFromVoiceAgentTodoEntry(entry, toolCall, parentArgs = {}, options = {}) {
  const args = normalizeVoiceAgentQueueArguments(entry);
  const text = normalizeTodoQueueText(
    cleanPublicVoiceAgentText(
      args.text
        || args.body
        || args.prompt
        || args.todo
        || args.task
        || toolCall?.text
        || "",
    ),
  );

  if (!text) {
    return null;
  }
  const entryTargetFields = getVoiceAgentQueueTargetFields(args);
  const parentTargetFields = getVoiceAgentQueueTargetFields(parentArgs);
  const selectedTargetFields = entryTargetFields.targetExplicit ? entryTargetFields : parentTargetFields;
  const resolvedTargetFields = typeof options.resolveTerminalTarget === "function"
    ? options.resolveTerminalTarget(selectedTargetFields) || null
    : null;
  const targetFields = resolvedTargetFields
    ? { ...selectedTargetFields, ...resolvedTargetFields, targetExplicit: true, userPinnedTarget: true }
    : selectedTargetFields;
  const itemId = String(args.id || args.todo_id || args.todoId || args.client_todo_id || args.clientTodoId || "").trim();

  const planTask = normalizeTodoQueuePlanTask({
    doneWhen: args.plan_done_when || args.planDoneWhen,
    maxConcurrency: args.plan_max_concurrency ?? args.planMaxConcurrency,
    releasePolicy: args.plan_release_policy || args.planReleasePolicy,
    requiresQueueDrain: args.plan_requires_queue_drain ?? args.planRequiresQueueDrain,
    runId: args.plan_run_id || args.planRunId,
    taskId: args.plan_task_id || args.planTaskId,
    stage: args.plan_stage || args.planStage,
    stepOrdinal: args.plan_step_ordinal ?? args.planStepOrdinal,
    title: args.plan_task_title || args.planTaskTitle || args.title,
  });

  return createTodoQueueItem(text, {
    ...(planTask ? {
      id: planTask.clientTodoId || planTask.taskId,
      planTask,
      source: TODO_QUEUE_SOURCE_VOICE_PLAN,
    } : {
      ...(itemId ? { id: itemId } : {}),
      source: TODO_QUEUE_SOURCE_VOICE_AGENT,
    }),
    title: args.title || "",
    ...targetFields,
  });
}

function getTodoQueuePendingFieldsFromItem(item, source = "") {
  const queueMeta = normalizeTodoQueueFlatQueueMetadata(item) || {};
  const remoteCommand = item?.remoteCommand && typeof item.remoteCommand === "object"
    ? item.remoteCommand
    : item?.remote_command && typeof item.remote_command === "object"
      ? item.remote_command
      : {};
  const targetInfo = getTodoQueueExplicitTerminalTargetInfo(item);
  const targetAgentId = getTodoQueueTargetAgentId(item);
  const targetColorSlot = getTodoQueueTargetColorSlot(item);
  const targetTerminalName = getTodoQueueTargetTerminalName(item);
  const targetTerminalColor = getTodoQueueTargetTerminalColor(item);
  const commandId = queueMeta.commandId || getTodoQueueRemoteCommandId(item);
  const dispatchId = queueMeta.dispatchId
    || queueMeta.todoDispatchId
    || getTodoQueueRemoteCommandDispatchId(item);
  const todoId = queueMeta.todoId
    || getTodoQueueItemTodoId(item)
    || String(remoteCommand.todoId || remoteCommand.todo_id || "").trim();
  const dispatchSource = remoteCommand.dispatchSource || remoteCommand.dispatch_source || item?.dispatchSource || item?.dispatch_source || null;
  const dispatchTarget = remoteCommand.dispatchTarget || remoteCommand.dispatch_target || item?.dispatchTarget || item?.dispatch_target || null;
  const targetExplicit = Boolean(targetInfo.hasExplicitTerminalTarget);
  return {
    source,
    ...(commandId ? { commandId } : {}),
    ...(dispatchId ? { dispatchId, todoDispatchId: dispatchId } : {}),
    ...(todoId ? { todoId } : {}),
    ...(dispatchSource && typeof dispatchSource === "object" ? { dispatchSource } : {}),
    ...(dispatchTarget && typeof dispatchTarget === "object" ? { dispatchTarget } : {}),
    ...(targetAgentId ? { targetAgentId, targetRole: targetAgentId } : {}),
    ...(Number.isInteger(targetColorSlot) ? { targetColorSlot } : {}),
    ...(targetTerminalColor ? { targetTerminalColor } : {}),
    ...(targetInfo.requestedTargetTerminalId ? { targetTerminalId: targetInfo.requestedTargetTerminalId } : {}),
    ...(Number.isInteger(targetInfo.requestedTargetTerminalIndex) ? { targetTerminalIndex: targetInfo.requestedTargetTerminalIndex } : {}),
    ...(targetTerminalName ? { targetTerminalName } : {}),
    ...(targetInfo.requestedTargetThreadId ? { targetThreadId: targetInfo.requestedTargetThreadId } : {}),
    ...(targetExplicit ? { targetExplicit: true, userPinnedTarget: true } : {}),
  };
}

function normalizeVoiceHistoryText(value, maxLength = TODO_QUEUE_MAX_TEXT_LENGTH) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .trim()
    .slice(0, maxLength);
}

// Reuse one formatter instead of rebuilding an ICU formatter (udat_open) on
// every call. List re-renders format a timestamp per item, which otherwise
// shows up as a CPU burst in CoreText/ICU during periodic refreshes.
const VOICE_HISTORY_TIME_FORMATTER = new Intl.DateTimeFormat([], {
  hour: "numeric",
  minute: "2-digit",
});

function formatVoiceHistoryMessageTime(value) {
  const timestamp = Number(value || 0);
  if (!Number.isFinite(timestamp) || timestamp <= 0) {
    return "";
  }

  return VOICE_HISTORY_TIME_FORMATTER.format(timestamp);
}

async function copyTextToClipboard(text) {
  const safeText = String(text || "");
  if (!safeText || typeof window === "undefined") {
    return false;
  }

  if (window.navigator?.clipboard?.writeText) {
    await window.navigator.clipboard.writeText(safeText);
    return true;
  }

  const textarea = window.document.createElement("textarea");
  textarea.value = safeText;
  textarea.setAttribute("readonly", "");
  textarea.style.position = "fixed";
  textarea.style.left = "-9999px";
  textarea.style.top = "0";
  window.document.body.appendChild(textarea);
  textarea.select();

  try {
    return window.document.execCommand("copy");
  } finally {
    textarea.remove();
  }
}

function getVoiceHistoryTurnIndex(event) {
  const value = event?.turn_index ?? event?.turnIndex;
  const numericValue = Number(value);
  return Number.isFinite(numericValue) ? numericValue : 0;
}

function getVoiceHistoryTurnKey(event, sessionId) {
  return `${Number(sessionId || 0)}:${getVoiceHistoryTurnIndex(event)}`;
}

function getVoiceHistoryTurnStatus(item) {
  const llmStatus = String(item?.llmStatus || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (llmStatus === "cancelled" || llmStatus === "canceled") {
    return "Cancelled";
  }
  if (llmStatus === "failed" || llmStatus === "error") {
    return "Failed";
  }
  if (llmStatus === "timed_out" || llmStatus === "timeout") {
    return "Timed out";
  }
  if (item?.plan) {
    return getVoicePlanStatusLabel(item.plan);
  }
  if (llmStatus === "planned") {
    return "Planned";
  }
  if (llmStatus === "ready") {
    return "Done";
  }
  if (!item?.transcriptFinal) {
    return "Pending";
  }
  if (item?.llmFinal || item?.queued) {
    return "Done";
  }
  if (item?.llmFeedback) {
    return "Thinking";
  }
  return "Thinking";
}

function getVoiceHistoryTurnLabel(item) {
  const turnIndex = Number(item?.turnIndex || 0);
  if (item?.plan?.title && !item.transcript) {
    return "Voice plan";
  }
  if (item?.source === "chat") {
    return `Chat turn ${turnIndex + 1}`;
  }
  return `Voice turn ${turnIndex + 1}`;
}

function normalizeVoiceHistoryToolCalls(value) {
  return (Array.isArray(value) ? value : [])
    .filter((call) => call && typeof call === "object")
    .map((call) => ({
      atMs: Number(call.atMs) || Date.now(),
      detail: String(call.detail || "").slice(0, 1600),
      id: String(call.id || "").trim(),
      name: String(call.name || "").trim().slice(0, 48),
      summary: normalizeVoiceHistoryText(call.summary, 220),
    }))
    .filter((call) => call.name)
    .slice(-12);
}

function normalizeOrchestratorVoiceHistoryItem(item) {
  if (!item || typeof item !== "object") {
    return null;
  }

  const id = String(item.id || "").trim();
  const transcript = normalizeVoiceHistoryText(item.transcript);
  const llmFeedback = normalizeVoiceHistoryText(item.llmFeedback, 1600);
  const llmError = normalizeVoiceHistoryText(item.llmError, 1600);
  const queuedText = normalizeVoiceHistoryText(item.queuedText, 600);
  const plan = normalizeVoicePlanSnapshot(item.plan);
  const toolCalls = normalizeVoiceHistoryToolCalls(item.toolCalls);
  if (!id || (!transcript && !llmFeedback && !llmError && !queuedText && !plan && !toolCalls.length)) {
    return null;
  }

  const createdAtMs = Number(item.createdAtMs || item.updatedAtMs || Date.now());
  const updatedAtMs = Number(item.updatedAtMs || createdAtMs || Date.now());
  const turnIndex = Number(item.turnIndex);

  return {
    createdAtMs: Number.isFinite(createdAtMs) ? createdAtMs : Date.now(),
    id,
    llmFeedback,
    llmError,
    llmFinal: Boolean(item.llmFinal),
    llmStatus: String(item.llmStatus || "").trim().slice(0, 48),
    ...(plan ? { plan } : {}),
    queued: Boolean(item.queued),
    queuedText,
    source: String(item.source || "").trim().slice(0, 32),
    engine: String(item.engine || "").trim().slice(0, 24),
    toolCalls,
    transcript,
    transcriptFinal: Boolean(item.transcriptFinal),
    turnIndex: Number.isFinite(turnIndex) ? turnIndex : 0,
    updatedAtMs: Number.isFinite(updatedAtMs) ? updatedAtMs : Date.now(),
  };
}

function normalizeVoicePlanSnapshot(value) {
  if (!value || typeof value !== "object") {
    return null;
  }
  const runId = String(value.runId || value.id || "").trim();
  if (!runId) {
    return null;
  }
  const steps = (Array.isArray(value.steps) ? value.steps : []).map((step, index) => {
    const ordinal = Number.isFinite(Number(step?.ordinal)) ? Number(step.ordinal) : index;
    return {
      executionStatus: String(step?.executionStatus || step?.execution_status || "").trim(),
      executionPolicy: String(step?.executionPolicy || step?.execution_policy || "").trim(),
      executionRequiresQueueDrain: Boolean(step?.executionRequiresQueueDrain || step?.execution_requires_queue_drain),
      executionDoneWhen: String(step?.executionDoneWhen || step?.execution_done_when || "").trim(),
      executionTasks: normalizeVoicePlanTasks(
        step?.executionTasks || step?.execution_tasks,
        { runId, stage: "execution", stepOrdinal: ordinal },
      ),
      objective: normalizeVoiceHistoryText(step?.objective, 600),
      ordinal,
      revisionStatus: String(step?.revisionStatus || step?.revision_status || "").trim(),
      revisionPolicy: String(step?.revisionPolicy || step?.revision_policy || "").trim(),
      revisionRequiresQueueDrain: Boolean(step?.revisionRequiresQueueDrain || step?.revision_requires_queue_drain),
      revisionDoneWhen: String(step?.revisionDoneWhen || step?.revision_done_when || "").trim(),
      revisionTasks: normalizeVoicePlanTasks(
        step?.revisionTasks || step?.revision_tasks,
        { runId, stage: "revision", stepOrdinal: ordinal },
      ),
      status: String(step?.status || "").trim(),
      title: normalizeVoiceHistoryText(step?.title, 160) || `Step ${index + 1}`,
    };
  });
  return {
    currentStage: String(value.currentStage || value.current_stage || "").trim(),
    currentStepOrdinal: Number.isFinite(Number(value.currentStepOrdinal ?? value.current_step_ordinal))
      ? Number(value.currentStepOrdinal ?? value.current_step_ordinal)
      : 0,
    goal: normalizeVoiceHistoryText(value.goal, 1200),
    runId,
    status: String(value.status || "").trim(),
    steps,
    title: normalizeVoiceHistoryText(value.title, 200) || "Voice plan",
    updatedAt: String(value.updatedAt || value.updated_at || "").trim(),
  };
}

function normalizeVoicePlanTasks(value, context = {}) {
  return (Array.isArray(value) ? value : []).map((task, index) => ({
    agentId: String(task?.agentId || task?.agent_id || "").trim(),
    clientTodoId: String(task?.clientTodoId || task?.client_todo_id || task?.todoId || task?.todo_id || "").trim(),
    id: String(task?.taskId || task?.id || "").trim(),
    ordinal: Number.isFinite(Number(task?.ordinal)) ? Number(task.ordinal) : index,
    promptEventId: String(task?.promptEventId || task?.prompt_event_id || "").trim(),
    requeueCount: Number.isFinite(Number(task?.requeueCount ?? task?.requeue_count))
      ? Number(task?.requeueCount ?? task?.requeue_count)
      : 0,
    requeuedAt: String(task?.requeuedAt || task?.requeued_at || "").trim(),
    releasePolicy: String(task?.releasePolicy || task?.release_policy || "").trim(),
    requiresQueueDrain: Boolean(task?.requiresQueueDrain || task?.requires_queue_drain),
    doneWhen: String(task?.doneWhen || task?.done_when || "").trim(),
    maxConcurrency: Number.isFinite(Number(task?.maxConcurrency ?? task?.max_concurrency))
      ? Number(task?.maxConcurrency ?? task?.max_concurrency)
      : 0,
    runId: String(task?.runId || task?.run_id || context.runId || "").trim(),
    stage: String(task?.stage || context.stage || "").trim(),
    status: String(task?.status || "").trim(),
    statusReason: String(task?.statusReason || task?.status_reason || task?.todoStatusReason || task?.todo_status_reason || "").trim(),
    statusSource: String(task?.statusSource || task?.status_source || "").trim(),
    stepOrdinal: Number.isFinite(Number(task?.stepOrdinal ?? task?.step_ordinal ?? context.stepOrdinal))
      ? Number(task?.stepOrdinal ?? task?.step_ordinal ?? context.stepOrdinal)
      : 0,
    targetTerminalColor: String(task?.targetTerminalColor || task?.target_terminal_color || "").trim(),
    terminalIndex: Number.isFinite(Number(task?.terminalIndex ?? task?.terminal_index))
      ? Number(task?.terminalIndex ?? task?.terminal_index)
      : null,
    terminalId: String(task?.terminalId || task?.terminal_id || task?.targetTerminalId || task?.target_terminal_id || "").trim(),
    text: normalizeVoiceHistoryText(task?.text, 420),
    threadId: String(task?.threadId || task?.thread_id || task?.targetThreadId || task?.target_thread_id || "").trim(),
    title: normalizeVoiceHistoryText(task?.title, 120),
    todoDerived: Boolean(task?.todoDerived || task?.todo_derived),
    todoStatus: String(task?.todoStatus || task?.todo_status || "").trim(),
  })).filter((task) => task.id || task.text);
}

function getVoicePlanStatusLabel(plan) {
  const status = String(plan?.status || "").trim().replace(/_/g, " ");
  if (status === "completed") {
    return "Complete";
  }
  if (status === "planned") {
    return "Planned";
  }
  if (status === "failed") {
    return "Failed";
  }
  if (status === "cancelled" || status === "canceled") {
    return "Cancelled";
  }
  const currentStep = Number(plan?.currentStepOrdinal || 0) + 1;
  const currentStage = String(plan?.currentStage || "").trim();
  if (currentStage) {
    return `Step ${currentStep} ${currentStage}`;
  }
  return status || "Plan";
}

function getVoicePlanTaskStatusLabel(task) {
  const status = String(task?.status || "").trim().replace(/_/g, " ");
  if (!status || status === "draft") {
    return "waiting";
  }
  if (status === "needs requeue") {
    return "requeue";
  }
  if (status === "timed out") {
    return "timed out";
  }
  if (status === "sent to client") {
    return "queued";
  }
  return status;
}

function getVoicePlanTaskControlPlanTask(plan, step, stageName, task) {
  return normalizeTodoQueuePlanTask({
    clientTodoId: task?.clientTodoId || task?.client_todo_id || task?.todoId || task?.todo_id,
    doneWhen: task?.doneWhen,
    maxConcurrency: task?.maxConcurrency,
    releasePolicy: task?.releasePolicy,
    requiresQueueDrain: task?.requiresQueueDrain,
    runId: task?.runId || plan?.runId || "",
    stage: task?.stage || stageName || "",
    stepOrdinal: task?.stepOrdinal ?? step?.ordinal ?? 0,
    taskId: task?.taskId || task?.id || "",
    text: task?.text || "",
    title: task?.title || "",
  });
}

function getVoicePlanReleasedTaskFromControlTask(plan, step, stageName, task) {
  const planTask = getVoicePlanTaskControlPlanTask(plan, step, stageName, task);
  const text = normalizeTodoQueueText(cleanPublicVoiceAgentText(task?.text || planTask?.text || task?.title || ""));
  if (!planTask || !text) {
    return null;
  }
  return {
    clientTodoId: planTask.clientTodoId || planTask.taskId,
    doneWhen: planTask.doneWhen,
    maxConcurrency: planTask.maxConcurrency,
    releasePolicy: planTask.releasePolicy,
    requiresQueueDrain: planTask.requiresQueueDrain,
    runId: planTask.runId,
    stage: planTask.stage,
    stepOrdinal: planTask.stepOrdinal,
    taskId: planTask.taskId,
    title: planTask.title || normalizeVoiceHistoryText(task?.title, 120),
    text,
  };
}

function voicePlanTaskMatchesPlanTask(item, planTask) {
  const normalizedPlanTask = normalizeTodoQueuePlanTask(planTask);
  if (!item?.id || !normalizedPlanTask?.taskId) {
    return false;
  }
  const itemId = String(item.id || "").trim();
  const clientTodoId = String(normalizedPlanTask.clientTodoId || normalizedPlanTask.taskId || "").trim();
  if (itemId === normalizedPlanTask.taskId || itemId === clientTodoId) {
    return true;
  }
  const itemPlanTask = getTodoQueueItemPlanTask(item);
  return Boolean(
    itemPlanTask
      && itemPlanTask.taskId === normalizedPlanTask.taskId
      && (!clientTodoId || itemPlanTask.clientTodoId === clientTodoId || itemId === clientTodoId)
      && (!normalizedPlanTask.runId || itemPlanTask.runId === normalizedPlanTask.runId),
  );
}

function getVoicePlanTaskLocalQueueMeta(planTask, items = [], pendingItems = {}) {
  const normalizedPlanTask = normalizeTodoQueuePlanTask(planTask);
  if (!normalizedPlanTask) {
    return {
      item: null,
      pendingItem: null,
      pendingPhase: "",
    };
  }
  const item = (Array.isArray(items) ? items : []).find((candidate) => (
    voicePlanTaskMatchesPlanTask(candidate, normalizedPlanTask)
  )) || null;
  const clientTodoId = String(normalizedPlanTask.clientTodoId || normalizedPlanTask.taskId || "").trim();
  const pendingItem = item?.id
    ? pendingItems?.[item.id] || pendingItems?.[clientTodoId] || pendingItems?.[normalizedPlanTask.taskId] || null
    : pendingItems?.[clientTodoId] || pendingItems?.[normalizedPlanTask.taskId] || null;
  return {
    item,
    pendingItem,
    pendingPhase: pendingItem ? getTodoQueuePendingPhase(pendingItem) : "",
  };
}

function getVoicePlanStatusFromWorkspaceTodo(todo) {
  const status = getTodoQueueCanonicalLifecycleStatus(todo);
  if (status === "completed") return "done";
  if (status === "queued") return "queued";
  if (status === "running") return "running";
  if (status === "paused") return "paused";
  if (status === "cancelled") return "cancelled";
  if (status === "interrupted") return "interrupted";
  if (status === "timed_out") return "timed_out";
  if (status === "failed") return "failed";
  if (status === "listed") return "sent_to_client";
  return "";
}

function getVoicePlanTaskUiStatus(
  task,
  planTask,
  items = [],
  pendingItems = {},
  workspaceTodos = null,
  workspaceId = "",
) {
  const { item, pendingItem, pendingPhase } = getVoicePlanTaskLocalQueueMeta(planTask, items, pendingItems);
  if (pendingPhase === "queued") {
    return "queued";
  }
  if (pendingPhase === "sending") {
    return "dispatched";
  }
  const localTodoStatus = item ? getVoicePlanStatusFromWorkspaceTodo(item) : "";
  if (localTodoStatus) {
    return localTodoStatus;
  }
  const workspaceTodoStatus = getVoicePlanStatusFromWorkspaceTodo(
    findWorkspaceTodoForVoicePlanTask(workspaceTodos, workspaceId, planTask),
  );
  if (workspaceTodoStatus) {
    return workspaceTodoStatus;
  }
  const taskTodoStatus = getVoicePlanStatusFromWorkspaceTodo(task);
  if (taskTodoStatus) {
    return taskTodoStatus;
  }
  const status = normalizeVoicePlanStatus(task?.status);
  if (
    !item
    && !pendingItem
    && (
      VOICE_PLAN_QUEUEABLE_STATUSES.has(status)
      || VOICE_PLAN_RUNNING_STATUSES.has(status)
      || VOICE_PLAN_PARKED_STATUSES.has(status)
    )
  ) {
    return "needs_requeue";
  }
  return status || "waiting";
}

function getVoicePlanTaskTone(status) {
  const normalized = normalizeVoicePlanStatus(status);
  if (isVoicePlanCompletedStatus(normalized)) {
    return "done";
  }
  if (VOICE_PLAN_FAILED_STATUSES.has(normalized)) {
    return "failed";
  }
  if (VOICE_PLAN_CANCELLED_STATUSES.has(normalized)) {
    return "cancelled";
  }
  if (VOICE_PLAN_INTERRUPTED_STATUSES.has(normalized)) {
    return "interrupted";
  }
  if (VOICE_PLAN_TIMED_OUT_STATUSES.has(normalized)) {
    return "failed";
  }
  if (normalized === "needs_requeue") {
    return "waiting";
  }
  if (VOICE_PLAN_RUNNING_STATUSES.has(normalized) || VOICE_PLAN_PARKED_STATUSES.has(normalized) || normalized === "paused") {
    return "running";
  }
  if (VOICE_PLAN_QUEUEABLE_STATUSES.has(normalized)) {
    return "queued";
  }
  return "waiting";
}

function getVoicePlanTaskControlAvailability({
  items = [],
  pendingItems = {},
  plan = null,
  planTask = null,
  task = null,
  workspaceId = "",
  workspaceTodos = null,
} = {}) {
  const normalizedPlanTask = normalizeTodoQueuePlanTask(planTask);
  const localState = getVoicePlanTaskLocalQueueMeta(normalizedPlanTask, items, pendingItems);
  const cloudTodo = findWorkspaceTodoForVoicePlanTask(workspaceTodos, workspaceId, normalizedPlanTask);
  const uiStatus = getVoicePlanTaskUiStatus(
    task,
    normalizedPlanTask,
    items,
    pendingItems,
    workspaceTodos,
    workspaceId,
  );
  const tone = getVoicePlanTaskTone(uiStatus);
  const planTone = getVoicePlanTaskTone(plan?.status);
  const hasLocalQueue = Boolean(localState.item || localState.pendingItem);
  const hasCloudTodo = Boolean(cloudTodo);
  const isDone = tone === "done";
  const isWaiting = VOICE_PLAN_WAITING_STATUSES.has(normalizeVoicePlanStatus(task?.status))
    && !hasLocalQueue
    && !hasCloudTodo;
  const canCancel = Boolean(
    normalizedPlanTask
      && !isDone
      && (
        hasLocalQueue
        || tone === "queued"
        || tone === "running"
      ),
  );
  const canRequeue = Boolean(
    normalizedPlanTask
      && !hasLocalQueue
      && !isDone
      && !isWaiting
      && tone !== "queued"
      && tone !== "running"
      && planTone !== "done",
  );
  return {
    canCancel,
    canRequeue,
    cloudTodo,
    hasCloudTodo,
    hasLocalQueue,
    localItem: localState.item,
    pendingItem: localState.pendingItem,
    pendingPhase: localState.pendingPhase,
    status: uiStatus,
    tone,
  };
}

function getVoicePlanProgressCounts(plan, items = [], pendingItems = {}, workspaceTodos = null, workspaceId = "") {
  const tasks = [];
  (Array.isArray(plan?.steps) ? plan.steps : []).forEach((step) => {
    VOICE_PLAN_STAGE_ORDER.forEach((stageName) => {
      getVoicePlanStageTasks(step, stageName).forEach((task) => {
        const planTask = getVoicePlanTaskControlPlanTask(plan, step, stageName, task);
        tasks.push(getVoicePlanTaskControlAvailability({
          items,
          pendingItems,
          plan,
          planTask,
          task,
          workspaceId,
          workspaceTodos,
        }));
      });
    });
  });
  const total = tasks.length;
  const done = tasks.filter((task) => task.tone === "done").length;
  const failed = tasks.filter((task) => task.tone === "failed").length;
  const interrupted = tasks.filter((task) => task.tone === "interrupted").length;
  const cancelled = tasks.filter((task) => task.tone === "cancelled").length;
  const active = tasks.filter((task) => task.tone === "queued" || task.tone === "running").length;
  const needsRequeue = tasks.filter((task) => task.status === "needs_requeue").length;
  return {
    active,
    cancelled,
    done,
    failed,
    interrupted,
    needsRequeue,
    total,
  };
}

function voicePlanHasCancellableWork(plan, items = [], pendingItems = {}, workspaceTodos = null, workspaceId = "") {
  const planTone = getVoicePlanTaskTone(plan?.status);
  if (planTone === "done" || planTone === "cancelled" || planTone === "failed" || planTone === "interrupted") {
    return false;
  }
  return (Array.isArray(plan?.steps) ? plan.steps : []).some((step) => (
    VOICE_PLAN_STAGE_ORDER.some((stageName) => (
      getVoicePlanStageTasks(step, stageName).some((task) => {
        const planTask = getVoicePlanTaskControlPlanTask(plan, step, stageName, task);
        return getVoicePlanTaskControlAvailability({
          items,
          pendingItems,
          plan,
          planTask,
          task,
          workspaceId,
          workspaceTodos,
        }).canCancel || getVoicePlanTaskTone(task?.status) !== "done";
      })
    ))
  ));
}

function voicePlanHasRequeueableWork(plan, items = [], pendingItems = {}, workspaceTodos = null, workspaceId = "") {
  return (Array.isArray(plan?.steps) ? plan.steps : []).some((step) => (
    VOICE_PLAN_STAGE_ORDER.some((stageName) => (
      getVoicePlanStageTasks(step, stageName).some((task) => {
        const planTask = getVoicePlanTaskControlPlanTask(plan, step, stageName, task);
        return getVoicePlanTaskControlAvailability({
          items,
          pendingItems,
          plan,
          planTask,
          task,
          workspaceId,
          workspaceTodos,
        }).canRequeue;
      })
    ))
  ));
}

function normalizeVoicePlanReleasedTask(value, snapshot = null) {
  if (!value || typeof value !== "object") {
    return null;
  }
  const runId = String(
    value.runId
      || value.run_id
      || value.planRunId
      || value.plan_run_id
      || snapshot?.runId
      || "",
  ).trim();
  const taskId = String(value.taskId || value.task_id || value.id || "").trim();
  const clientTodoId = String(value.clientTodoId || value.client_todo_id || value.todoId || value.todo_id || "").trim();
  const text = normalizeTodoQueueText(cleanPublicVoiceAgentText(value.text || value.todo || value.task || ""));
  if (!runId || !taskId || !text) {
    return null;
  }
  return {
    clientTodoId: clientTodoId || taskId,
    doneWhen: String(value.doneWhen || value.done_when || value.planDoneWhen || value.plan_done_when || "").trim(),
    maxConcurrency: Number.isFinite(Number(value.maxConcurrency ?? value.max_concurrency ?? value.planMaxConcurrency ?? value.plan_max_concurrency))
      ? Number(value.maxConcurrency ?? value.max_concurrency ?? value.planMaxConcurrency ?? value.plan_max_concurrency)
      : 0,
    releasePolicy: String(value.releasePolicy || value.release_policy || value.planReleasePolicy || value.plan_release_policy || "").trim(),
    requiresQueueDrain: Boolean(value.requiresQueueDrain || value.requires_queue_drain || value.planRequiresQueueDrain || value.plan_requires_queue_drain),
    runId,
    stage: String(value.stage || value.planStage || value.plan_stage || snapshot?.currentStage || "").trim(),
    stepOrdinal: Number.isFinite(Number(value.stepOrdinal ?? value.step_ordinal ?? snapshot?.currentStepOrdinal))
      ? Number(value.stepOrdinal ?? value.step_ordinal ?? snapshot?.currentStepOrdinal)
      : 0,
    taskId,
    title: normalizeVoiceHistoryText(value.title, 120),
    text,
  };
}

function unwrapCloudVoicePlanResult(value) {
  if (!value || typeof value !== "object") {
    return null;
  }
  if (value.plan_snapshot || value.planSnapshot || value.snapshot || value.released_tasks || value.releasedTasks) {
    return value;
  }
  const data = value.data && typeof value.data === "object" ? value.data : null;
  if (data?.plan_snapshot || data?.planSnapshot || data?.snapshot || data?.released_tasks || data?.releasedTasks) {
    return data;
  }
  const nested = data?.data && typeof data.data === "object" ? data.data : null;
  if (nested?.plan_snapshot || nested?.planSnapshot || nested?.snapshot || nested?.released_tasks || nested?.releasedTasks) {
    return nested;
  }
  return data || null;
}

function getVoicePlanSnapshotFromPayload(value) {
  const payload = unwrapCloudVoicePlanResult(value);
  return normalizeVoicePlanSnapshot(
    payload?.plan_snapshot
      || payload?.planSnapshot
      || payload?.snapshot
      || value?.snapshot
      || value,
  );
}

function getVoicePlanReleasedTasksFromPayload(value, snapshot = null) {
  const payload = unwrapCloudVoicePlanResult(value);
  const rawTasks = payload?.released_tasks || payload?.releasedTasks || [];
  const releasedTasks = (Array.isArray(rawTasks) ? rawTasks : [])
    .map((task) => normalizeVoicePlanReleasedTask(task, snapshot))
    .filter(Boolean);
  if (releasedTasks.length) {
    return releasedTasks;
  }
  return getVoicePlanReleasedTasksFromSnapshot(snapshot || getVoicePlanSnapshotFromPayload(value));
}

function getVoicePlanTaskFromPromptEventId(value) {
  const taskId = String(value || "").trim();
  if (!taskId.startsWith("voice-plan-")) {
    return null;
  }
  const match = taskId.match(/^(voice-plan-.+)-s\d+-(execution|revision)-t\d+$/);
  if (!match) {
    return null;
  }
  return normalizeTodoQueuePlanTask({
    runId: match[1],
    stage: match[2],
    taskId,
  });
}

function normalizeOrchestratorVoiceHistoryItems(items) {
  return (Array.isArray(items) ? items : [])
    .map(normalizeOrchestratorVoiceHistoryItem)
    .filter(Boolean)
    .sort((left, right) => (
      Number(left.createdAtMs || left.updatedAtMs || 0)
      - Number(right.createdAtMs || right.updatedAtMs || 0)
    ))
    .slice(-ORCHESTRATOR_VOICE_HISTORY_MAX_TURNS);
}

function getTodoQueueItemNote(item) {
  return normalizeTodoQueueNote(item?.note || item?.noteText || item?.longText);
}

function normalizeTodoQueuePlanTask(value) {
  if (!value || typeof value !== "object") {
    return null;
  }
  const runId = String(value.runId || value.run_id || value.planRunId || value.plan_run_id || "").trim();
  const taskId = String(value.taskId || value.task_id || value.planTaskId || value.plan_task_id || value.id || "").trim();
  const clientTodoId = String(value.clientTodoId || value.client_todo_id || value.todoId || value.todo_id || "").trim();
  if (!runId || !taskId) {
    return null;
  }
  return {
    clientTodoId: clientTodoId || taskId,
    doneWhen: String(value.doneWhen || value.done_when || value.planDoneWhen || value.plan_done_when || "").trim(),
    maxConcurrency: Number.isFinite(Number(value.maxConcurrency ?? value.max_concurrency ?? value.planMaxConcurrency ?? value.plan_max_concurrency))
      ? Number(value.maxConcurrency ?? value.max_concurrency ?? value.planMaxConcurrency ?? value.plan_max_concurrency)
      : 0,
    releasePolicy: String(value.releasePolicy || value.release_policy || value.planReleasePolicy || value.plan_release_policy || "").trim(),
    requiresQueueDrain: Boolean(value.requiresQueueDrain || value.requires_queue_drain || value.planRequiresQueueDrain || value.plan_requires_queue_drain),
    runId,
    title: normalizeVoiceHistoryText(value.title, 120),
    text: normalizeVoiceHistoryText(value.text || value.todo || value.task, 420),
    taskId,
    stage: String(value.stage || value.planStage || value.plan_stage || "").trim(),
    stepOrdinal: Number.isFinite(Number(value.stepOrdinal ?? value.step_ordinal))
      ? Number(value.stepOrdinal ?? value.step_ordinal)
      : 0,
  };
}

function getTodoQueueItemPlanTask(item) {
  return normalizeTodoQueuePlanTask(item?.planTask || item?.plan_task);
}

function isVoicePlanBoundaryQueueItem(item) {
  const planTask = getTodoQueueItemPlanTask(item);
  const releasePolicy = String(planTask?.releasePolicy || "").trim();
  return Boolean(
    planTask
      && (
        planTask.requiresQueueDrain
        || releasePolicy === "verification_barrier"
      ),
  );
}

function normalizeVoicePlanStageName(value) {
  return String(value || "").trim();
}

function getVoicePlanStageIndex(value) {
  return VOICE_PLAN_STAGE_ORDER.indexOf(normalizeVoicePlanStageName(value));
}

function normalizeVoicePlanStatus(value) {
  return String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
}

function isVoicePlanCompletedStatus(value) {
  const normalized = normalizeVoicePlanStatus(value);
  return VOICE_PLAN_COMPLETED_STATUSES.has(normalized)
    || VOICE_PLAN_COMPLETED_STATUSES.has(normalized.replace(/_/g, " "));
}

function getVoicePlanStepByOrdinal(plan, ordinal) {
  const stepOrdinal = Number(ordinal);
  if (!Number.isFinite(stepOrdinal)) {
    return null;
  }
  return (Array.isArray(plan?.steps) ? plan.steps : []).find((step) => (
    Number(step?.ordinal) === stepOrdinal
  )) || null;
}

function getVoicePlanStageStatus(step, stageName) {
  const stage = normalizeVoicePlanStageName(stageName);
  if (stage === "execution") {
    return String(step?.executionStatus || "").trim();
  }
  if (stage === "revision") {
    return String(step?.revisionStatus || "").trim();
  }
  return "";
}

function getVoicePlanStageTasks(step, stageName) {
  const stage = normalizeVoicePlanStageName(stageName);
  if (stage === "execution") {
    return Array.isArray(step?.executionTasks) ? step.executionTasks : [];
  }
  if (stage === "revision") {
    return Array.isArray(step?.revisionTasks) ? step.revisionTasks : [];
  }
  return [];
}

function getVoicePlanSnapshotTask(snapshot, planTask) {
  const normalizedPlanTask = normalizeTodoQueuePlanTask(planTask);
  if (!snapshot?.runId || !normalizedPlanTask) {
    return null;
  }
  const taskStepOrdinal = Number(normalizedPlanTask.stepOrdinal || 0);
  const taskStage = normalizeVoicePlanStageName(
    normalizedPlanTask.stage || snapshot.currentStage || "execution",
  );
  const step = getVoicePlanStepByOrdinal(snapshot, taskStepOrdinal);
  return getVoicePlanStageTasks(step, taskStage).find((task) => (
    String(task?.id || task?.taskId || "").trim() === normalizedPlanTask.taskId
  )) || null;
}

function isVoicePlanStageComplete(step, stageName) {
  if (!step) {
    return false;
  }
  const status = getVoicePlanStageStatus(step, stageName);
  if (isVoicePlanCompletedStatus(status)) {
    return true;
  }
  const tasks = getVoicePlanStageTasks(step, stageName);
  if (!tasks.length) {
    return !status;
  }
  return tasks.every((task) => isVoicePlanCompletedStatus(task?.status));
}

function isVoicePlanStepComplete(step) {
  if (!step) {
    return false;
  }
  if (isVoicePlanCompletedStatus(step?.status)) {
    return true;
  }
  return VOICE_PLAN_STAGE_ORDER.every((stageName) => isVoicePlanStageComplete(step, stageName));
}

function getVoicePlanTaskReleaseDecision(task, snapshot = null) {
  const planTask = normalizeTodoQueuePlanTask(task);
  if (!planTask) {
    return { eligible: false, reason: "invalid_plan_task" };
  }

  const taskStepOrdinal = Number(planTask.stepOrdinal || 0);
  const taskStage = normalizeVoicePlanStageName(planTask.stage || snapshot?.currentStage || "execution");
  const taskStageIndex = getVoicePlanStageIndex(taskStage);
  if (taskStageIndex < 0) {
    return { eligible: false, reason: "invalid_stage" };
  }
  if (isVoicePlanCompletedStatus(snapshot?.status)) {
    return { eligible: false, reason: "plan_complete" };
  }
  if (!snapshot?.runId) {
    return taskStepOrdinal === 0 && taskStageIndex === 0
      ? { eligible: true, reason: "first_slot_without_snapshot" }
      : { eligible: false, reason: "missing_plan_snapshot" };
  }
  if (planTask.runId && snapshot.runId && planTask.runId !== snapshot.runId) {
    return { eligible: false, reason: "plan_snapshot_mismatch" };
  }

  const currentStepOrdinal = Number(snapshot.currentStepOrdinal);
  const currentStage = normalizeVoicePlanStageName(snapshot.currentStage);
  const currentStageIndex = getVoicePlanStageIndex(currentStage);
  if (Number.isFinite(currentStepOrdinal)) {
    if (taskStepOrdinal < currentStepOrdinal) {
      return { eligible: false, reason: "past_step" };
    }
    if (
      taskStepOrdinal === currentStepOrdinal
      && currentStage
      && taskStage
      && taskStageIndex >= 0
      && currentStageIndex >= 0
    ) {
      if (taskStageIndex < currentStageIndex) {
        return { eligible: false, reason: "past_stage" };
      }
      if (taskStageIndex === currentStageIndex) {
        return { eligible: true, reason: "current_stage" };
      }
    }
  }

  const steps = Array.isArray(snapshot.steps) ? snapshot.steps : [];
  for (const step of steps) {
    const stepOrdinal = Number(step?.ordinal);
    if (Number.isFinite(stepOrdinal) && stepOrdinal < taskStepOrdinal && !isVoicePlanStepComplete(step)) {
      return { eligible: false, reason: "previous_step_incomplete" };
    }
  }
  const currentStep = getVoicePlanStepByOrdinal(snapshot, taskStepOrdinal);
  for (const stageName of VOICE_PLAN_STAGE_ORDER) {
    const stageIndex = getVoicePlanStageIndex(stageName);
    if (stageIndex >= taskStageIndex || stageIndex < 0) {
      continue;
    }
    if (!isVoicePlanStageComplete(currentStep, stageName)) {
      return { eligible: false, reason: "previous_stage_incomplete" };
    }
  }

  return { eligible: true, reason: "previous_slots_complete" };
}

function shouldDeferVoicePlanTaskRelease(reason) {
  return [
    "future_stage",
    "future_step",
    "missing_plan_snapshot",
    "previous_stage_incomplete",
    "previous_step_incomplete",
  ].includes(String(reason || ""));
}

function isVoicePlanClientReleaseStatus(value) {
  return VOICE_PLAN_CLIENT_RELEASE_STATUSES.has(normalizeVoicePlanStatus(value));
}

function getVoicePlanReleasedTaskKey(task) {
  return `${task?.runId || "plan"}:${task?.taskId || task?.id || ""}`;
}

function getVoicePlanTaskStatusLogSummary(task) {
  if (!task) {
    return null;
  }
  return {
    clientTodoId: task.clientTodoId || task.client_todo_id || task.todoId || task.todo_id || "",
    requeueCount: task.requeueCount ?? task.requeue_count ?? 0,
    requeuedAt: task.requeuedAt || task.requeued_at || "",
    runId: task.runId || task.run_id || task.planRunId || task.plan_run_id || "",
    stage: task.stage || task.planStage || task.plan_stage || "",
    stepOrdinal: task.stepOrdinal ?? task.step_ordinal ?? "",
    status: task.status || "",
    statusSource: task.statusSource || task.status_source || "",
    taskId: task.taskId || task.task_id || task.id || task.planTaskId || task.plan_task_id || "",
    todoStatus: task.todoStatus || task.todo_status || "",
    textLength: String(task.text || task.todo || task.task || "").length,
    title: task.title || "",
  };
}

function getVoicePlanSnapshotLogSummary(snapshot) {
  if (!snapshot) {
    return null;
  }
  return {
    currentStage: snapshot.currentStage || "",
    currentStepOrdinal: snapshot.currentStepOrdinal ?? "",
    runId: snapshot.runId || "",
    status: snapshot.status || "",
    stepCount: Array.isArray(snapshot.steps) ? snapshot.steps.length : 0,
    steps: (Array.isArray(snapshot.steps) ? snapshot.steps : []).map((step) => ({
      executionStatus: step?.executionStatus || "",
      executionTaskStatuses: (Array.isArray(step?.executionTasks) ? step.executionTasks : [])
        .map((task) => ({
          id: task?.id || task?.taskId || "",
          status: task?.status || "",
        })),
      ordinal: step?.ordinal ?? "",
      revisionStatus: step?.revisionStatus || "",
      revisionTaskStatuses: (Array.isArray(step?.revisionTasks) ? step.revisionTasks : [])
        .map((task) => ({
          id: task?.id || task?.taskId || "",
          status: task?.status || "",
        })),
      status: step?.status || "",
    })),
  };
}

function getVoicePlanReleasedTasksFromSnapshot(snapshot) {
  if (!snapshot?.runId) {
    return [];
  }
  const currentStepOrdinal = Number(snapshot.currentStepOrdinal || 0);
  const currentStage = normalizeVoicePlanStageName(snapshot.currentStage);
  const releasedTasks = [];
  (Array.isArray(snapshot.steps) ? snapshot.steps : []).forEach((step) => {
    const stepOrdinal = Number.isFinite(Number(step?.ordinal)) ? Number(step.ordinal) : 0;
    const stages = currentStage && stepOrdinal === currentStepOrdinal
      ? [currentStage]
      : VOICE_PLAN_STAGE_ORDER;
    stages.forEach((stageName) => {
      getVoicePlanStageTasks(step, stageName).forEach((task) => {
        if (!isVoicePlanClientReleaseStatus(task?.status)) {
          return;
        }
        releasedTasks.push({
          doneWhen: task.doneWhen,
          maxConcurrency: task.maxConcurrency,
          releasePolicy: task.releasePolicy,
          requiresQueueDrain: task.requiresQueueDrain,
          runId: task.runId || snapshot.runId,
          stage: task.stage || stageName,
          stepOrdinal: task.stepOrdinal ?? stepOrdinal,
          taskId: task.id || task.taskId,
          title: task.title,
          text: task.text,
        });
      });
    });
  });
  return releasedTasks
    .map((task) => normalizeVoicePlanReleasedTask(task, snapshot))
    .filter(Boolean);
}

function getTodoQueueNoteFromPastedText(value) {
  return getTodoQueueLineCount(value) > TODO_QUEUE_NOTE_LINE_THRESHOLD
    ? normalizeTodoQueueNote(value)
    : null;
}

function normalizeTodoTerminalPromptPart(value) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeTodoQueueImage(value) {
  const image = typeof value === "string"
    ? { src: value }
    : value && typeof value === "object"
      ? value
      : null;
  const src = typeof image?.src === "string" ? image.src.trim() : "";

  if (!src || !src.startsWith("data:image/")) {
    return null;
  }

  return {
    name: typeof image.name === "string" ? image.name.slice(0, 160) : "",
    size: Number(image.size || 0),
    src,
    type: typeof image.type === "string" ? image.type.slice(0, 80) : "",
  };
}

function dedupeTodoQueueImages(images) {
  const seenSources = new Set();

  return (Array.isArray(images) ? images : [])
    .map(normalizeTodoQueueImage)
    .filter((image) => {
      if (!image || seenSources.has(image.src)) {
        return false;
      }

      seenSources.add(image.src);
      return true;
    });
}

function getTodoQueueItemImages(item) {
  if (!item || typeof item !== "object") {
    return [];
  }

  return dedupeTodoQueueImages([
    ...(Array.isArray(item.images) ? item.images : []),
    ...(Array.isArray(item.imageAttachments) ? item.imageAttachments : []),
    ...(Array.isArray(item.image_attachments) ? item.image_attachments : []),
    item.image,
    item.imageDataUrl,
    item.image_data_url,
    item.imageSrc,
    item.image_src,
  ].filter(Boolean));
}

function getTodoQueueItemWithImages(item, images) {
  const nextItem = item && typeof item === "object" ? { ...item } : {};
  const nextImages = dedupeTodoQueueImages(images);

  delete nextItem.image;
  delete nextItem.images;
  delete nextItem.imageAttachments;
  delete nextItem.image_attachments;
  delete nextItem.imageDataUrl;
  delete nextItem.image_data_url;
  delete nextItem.imageSrc;
  delete nextItem.image_src;

  if (nextImages[0]) {
    nextItem.image = nextImages[0];
  }
  if (nextImages.length > 1) {
    nextItem.images = nextImages;
  }

  return nextItem;
}

function getTodoQueueItemWithoutNote(item) {
  const nextItem = item && typeof item === "object" ? { ...item } : {};

  delete nextItem.note;
  delete nextItem.noteText;
  delete nextItem.note_text;
  delete nextItem.longText;
  delete nextItem.long_text;

  return nextItem;
}

function getTodoQueueItemImage(item) {
  return getTodoQueueItemImages(item)[0] || null;
}

function getTodoQueueItemTerminalText(item) {
  const text = normalizeTodoQueueText(item?.text);
  const note = getTodoQueueItemNote(item);

  if (text && note?.text) {
    return `${text}\n\n${note.text}`;
  }

  return text || note?.text || "";
}

function getTodoQueueItemThreadMessageText(item, fallback = "") {
  return getTodoQueueItemTerminalText(item) || String(fallback || "");
}

function getTodoQueueItemAutoQueueSource(item) {
  return getTodoQueueAutoQueueSourceForSource({
    source: item?.source,
  });
}

function getTodoQueueAttachmentSource(source) {
  if (source === TODO_QUEUE_SOURCE_VOICE_AGENT) {
    return "tui_voice_agent_queue";
  }
  if (source === TODO_QUEUE_SOURCE_VOICE_PLAN) {
    return "tui_voice_plan_queue";
  }
  return source === TODO_QUEUE_SOURCE_TODO_AUTO ? "tui_todo_auto_queue" : "tui_todo_drop";
}

function getTodoQueuePromptEventSource(source) {
  return getTodoQueuePromptEventSourceForSource({
    source,
  });
}

function getTodoQueueLifecycleSource(source) {
  return getTodoQueueLifecycleSourceForSource({
    source,
  });
}

function todoQueueTerminalDirectLifecycleEventType(value) {
  return String(value || "").trim().toLowerCase().replace(/_/g, "-");
}

// Cross-path dedupe for terminal-direct todos is identity-based: the Rust
// capture (input gate or UserPromptSubmit hook) is the id authority and the
// webview materializer derives the same id per submission, so id/promptId
// matching alone is enough. Same-text recency matching was removed — it
// swallowed deliberately repeated prompts instead of giving each its own todo.

function todoQueueTerminalDirectSourceIsEligible(value) {
  const source = String(value || "").trim().toLowerCase();
  return source === "tui-manual-input"
    || source.startsWith("tui-manual-input:")
    || source === "observed-terminal-prompt"
    || source === "observed_terminal_prompt"
    || source === "terminal-prompt-submitted"
    || source === "terminal_prompt_submitted";
}

function todoQueueLifecycleEventHasTodoQueueOwner(event = {}) {
  const source = normalizeTodoQueueSource(
    event.source
      || event.messageSource
      || event.message_source
      || event.promptEventSource
      || event.prompt_event_source
      || "",
  );
  const normalizedSource = String(source || "").trim().toLowerCase();
  if (
    normalizedSource === TODO_QUEUE_SOURCE_TERMINAL_DIRECT
    || normalizedSource === TODO_QUEUE_SOURCE_TODO_AUTO
    || normalizedSource === TODO_QUEUE_SOURCE_VOICE_AGENT
    || normalizedSource === TODO_QUEUE_SOURCE_VOICE_PLAN
    || normalizedSource === TODO_QUEUE_SOURCE_REMOTE_CONTROL
    || normalizedSource === "tui-todo-drop"
    || normalizedSource === "terminal-view-drop"
    || normalizedSource === "todo-auto-queue"
    || normalizedSource === "terminal-direct-input"
    || normalizedSource === "voice-agent-queue"
    || normalizedSource === "voice-plan-queue"
    || normalizedSource === "remote-control"
  ) {
    return true;
  }

  return Boolean(
    event.todoId
      || event.todo_id
      || event.todoDispatchId
      || event.todo_dispatch_id
      || event.todoCommandId
      || event.todo_command_id
      || event.remoteCommand
      || event.remote_command,
  );
}

function getTodoQueueTerminalDirectLifecycleText(event = {}) {
  return normalizeTodoQueueText(
    event.userMessage
      || event.user_message
      || event.pendingPromptText
      || event.pending_prompt_text
      || event.expectedUserMessage
      || event.expected_user_message
      || event.terminalPrompt
      || event.terminal_prompt
      || event.promptText
      || event.prompt_text
      || "",
  );
}

function getTodoQueueTerminalDirectPromptId(event = {}, terminalIndex = null, text = "", submittedAt = "") {
  const promptId = String(
    event.promptEventId
      || event.prompt_event_id
      || event.pendingPromptId
      || event.pending_prompt_id
      || event.messageId
      || event.message_id
      || event.turnId
      || event.turn_id
      || "",
  ).trim();
  if (promptId) {
    return promptId;
  }

  const fallbackSource = [
    terminalIndex ?? "terminal",
    submittedAt || event.messageCreatedAt || event.message_created_at || "",
    text,
  ].join(":");
  let hash = 0;
  for (let index = 0; index < fallbackSource.length; index += 1) {
    hash = ((hash << 5) - hash + fallbackSource.charCodeAt(index)) | 0;
  }
  return `terminal-direct-${Math.abs(hash).toString(16)}-${Date.now().toString(36)}`;
}

function getTodoQueueTerminalDirectItemId(promptId) {
  const safePromptId = String(promptId || "")
    .trim()
    .replace(/[^a-zA-Z0-9_.:-]+/g, "_")
    .slice(0, 160);
  return `terminal-direct-${safePromptId || Date.now().toString(36)}`;
}

function normalizeTodoTerminalAgentId(value) {
  return String(value || "").trim().toLowerCase().replace(/[_\s]+/g, "-");
}

function resolveTodoQueueTerminalAgentRole(...values) {
  for (const value of values) {
    const raw = String(value || "").trim();
    if (!raw) {
      continue;
    }
    const agentKind = getTerminalAgentKind(raw);
    if (TODO_QUEUE_AGENT_ROLES.has(agentKind)) {
      return agentKind;
    }
    const normalized = normalizeTodoTerminalAgentId(raw);
    if (TODO_QUEUE_AGENT_ROLES.has(normalized)) {
      return normalized;
    }
  }
  return "";
}

const TODO_QUEUE_IGNORED_READINESS_EVENT_TYPES = new Set([
  "terminal-input-ready",
  "terminal-prompt-ready",
]);

const TODO_QUEUE_PROVIDER_HOOK_COMPLETION_EVENT_TYPES = new Set([
  "provider-turn-completed",
  "provider-turn-error",
  "provider-turn-interrupted",
]);

const TODO_QUEUE_PROVIDER_HOOK_PROMPT_SUBMIT_EVENT_TYPES = new Set([
  "provider-turn-started",
]);

const TODO_QUEUE_PROVIDER_HOOK_PROMPT_SUBMIT_NAMES = new Set([
  "prompt-submit",
  "prompt-submitted",
  "promptsubmit",
  "promptsubmitted",
  "user-prompt-submit",
  "user-prompt-submitted",
  "userpromptsubmit",
  "userpromptsubmitted",
]);

function todoQueueAgentUsesActivityHooks(value) {
  return terminalAgentUsesActivityHooks(normalizeTodoTerminalAgentId(value));
}

function todoQueueTerminalRoleCanReceiveTodos(value) {
  return TODO_QUEUE_AGENT_ROLES.has(normalizeTodoTerminalAgentId(value));
}

function todoQueueAgentUsesBackendHookSubmit(value) {
  return todoQueueAgentUsesActivityHooks(value);
}

function todoQueueComposerDraftIsTodoOwned(record) {
  const source = normalizeTodoTerminalAgentId(record?.source || "");
  const transactionId = normalizeTodoTerminalAgentId(record?.transactionId || "");
  return source.includes("todo_queue")
    || source.includes("tui_todo")
    || transactionId.includes("todo_drop")
    || transactionId.includes("todo_queue");
}

function clearTodoQueueBackendSubmitComposerDraft(syncKey, expectedText, options = {}) {
  const record = getWorkspaceThreadComposerDraftRecord(syncKey);
  const currentValue = String(record.value || "");
  const expectedValue = String(expectedText || "");
  if (!syncKey) {
    return { ...record, cleared: false, reason: "missing_sync_key" };
  }
  if (!currentValue) {
    return { ...record, cleared: false, reason: "empty_draft" };
  }

  const exactTodoText = Boolean(expectedValue && currentValue === expectedValue);
  const todoOwned = todoQueueComposerDraftIsTodoOwned(record);
  if (!exactTodoText && !todoOwned) {
    return { ...record, cleared: false, reason: "draft_not_owned_by_todo_submit" };
  }

  const nextRecord = setWorkspaceThreadComposerDraft(syncKey, "", {
    forceRevision: true,
    source: options.source || "todo_queue_backend_submit_stale_clear",
    transactionId: options.transactionId || record.transactionId || "",
  });
  return {
    ...nextRecord,
    cleared: true,
    previousRevision: record.revision || 0,
    previousSource: record.source || "",
    previousValue: currentValue,
    reason: exactTodoText ? "exact_todo_draft" : "todo_owned_draft",
  };
}

