        accepted: currentInFlightPrompt?.accepted === true,
        acceptedAt: currentInFlightPrompt?.acceptedAt || "",
        acceptedAtMs: currentInFlightPrompt?.acceptedAtMs || 0,
        acceptedMatchedBy: currentInFlightPrompt?.acceptedMatchedBy || "",
        completedAt,
